{
  "name": "ModelEval Pro",
  "description": "A professional visualization tool for batch evaluation of model outputs (Images & Videos) with side-by-side comparison and voting capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface EvaluationItem {
  id: string;
  modelA_Url: string; // Control or Model A
  modelB_Url: string; // Treatment or Model B
  type: 'image' | 'video' | 'unknown';
}

export type VoteType = 'A' | 'B' | 'Tie';

export interface VoteRecord {
  itemId: string;
  vote: VoteType;
  timestamp: number;
}

export type AppState = 'setup' | 'voting' | 'results';

export interface VotingStats {
  total: number;
  aCount: number;
  bCount: number;
  tieCount: number;
}

export const VIDEO_EXTENSIONS = ['mp4', 'webm', 'ogg', 'mov', 'm4v'];

export const SAMPLE_DATA = [
  {
    "modelA": "https://picsum.photos/seed/a1/800/600",
    "modelB": "https://picsum.photos/seed/b1/800/600"
  },
  {
    "modelA": "https://picsum.photos/seed/a2/800/600",
    "modelB": "https://picsum.photos/seed/b2/800/600"
  }
];

export const KEYBOARD_SHORTCUTS = {
  A: ['1', 'ArrowLeft'],
  B: ['2', 'ArrowRight'],
  TIE: ['3', 'ArrowDown', 'Enter'],
};

import React, { useState, useEffect } from 'react';
import { AlertCircle, FileVideo, Image as ImageIcon, Loader2 } from 'lucide-react';
import { VIDEO_EXTENSIONS } from '../constants';

interface MediaRendererProps {
  url: string;
  label: string;
  isActive: boolean;
}

const MediaRenderer: React.FC<MediaRendererProps> = ({ url, label, isActive }) => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [mediaType, setMediaType] = useState<'image' | 'video'>('image');

  // Simple heuristic to detect type from URL extension
  useEffect(() => {
    setLoading(true);
    setError(false);

    // Reset based on URL change
    const cleanUrl = url.split('?')[0].toLowerCase();
    const isVideo = VIDEO_EXTENSIONS.some(ext => cleanUrl.endsWith(`.${ext}`));
    setMediaType(isVideo ? 'video' : 'image');
  }, [url]);

  const handleLoad = () => setLoading(false);
  const handleError = () => {
    setLoading(false);
    setError(true);
  };

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-900 rounded-xl overflow-hidden border border-slate-700 shadow-xl group">
      {/* Label Badge */}
      <div className="absolute top-4 left-4 z-10 bg-black/60 backdrop-blur-md text-white px-3 py-1 rounded-full text-xs font-semibold tracking-wider border border-white/10">
        {label}
      </div>

      {/* Loading State */}
      {loading && !error && (
        <div className="absolute inset-0 flex items-center justify-center bg-slate-800 z-0">
          <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
        </div>
      )}

      {/* Error State */}
      {error && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-800 text-slate-400 p-4 text-center">
          <AlertCircle className="w-10 h-10 mb-2 text-red-400" />
          <p className="text-sm">Failed to load media.</p>
          <p className="text-xs opacity-50 break-all mt-1">{url}</p>
        </div>
      )}

      {/* Media Content */}
      <div className="flex-1 relative flex items-center justify-center bg-slate-950">
        {mediaType === 'video' ? (
          <video
            src={url}
            className="max-w-full max-h-full object-contain"
            controls
            autoPlay={isActive}
            loop
            muted
            onLoadedData={handleLoad}
            onError={handleError}
          />
        ) : (
          <img
            src={url}
            alt={label}
            className="max-w-full max-h-full object-contain"
            onLoad={handleLoad}
            onError={handleError}
          />
        )}
      </div>

      {/* Type Indicator (Bottom Right) */}
      <div className="absolute bottom-4 right-4 bg-black/40 backdrop-blur-sm p-1.5 rounded-lg text-white/70">
        {mediaType === 'video' ? <FileVideo size={16} /> : <ImageIcon size={16} />}
      </div>
    </div>
  );
};

export default MediaRenderer;

import React, { useState } from 'react';
import { Upload, Play, Info, AlertTriangle } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_DATA } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[]) => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ onStart }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState<string | null>(null);

  const parseInput = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please enter some data first.");
      return;
    }

    const items: EvaluationItem[] = [];

    // Try parsing as JSON
    try {
      const parsed = JSON.parse(inputText);
      if (Array.isArray(parsed)) {
        parsed.forEach((item, index) => {
          // Flexible key detection
          const urlA = item.modelA || item.urlA || item.control || item.a || item[0];
          const urlB = item.modelB || item.urlB || item.treatment || item.b || item[1];

          if (urlA && urlB) {
            items.push({
              id: `item-${index}`,
              modelA_Url: String(urlA),
              modelB_Url: String(urlB),
              type: 'unknown' // Will be detected by renderer
            });
          }
        });
      }
    } catch (e) {
      // If JSON fails, try CSV/Line-based
      const lines = inputText.split('\n');
      lines.forEach((line, index) => {
        const parts = line.split(/[,\t]+/).map(s => s.trim()).filter(Boolean);
        if (parts.length >= 2) {
          items.push({
            id: `item-${index}`,
            modelA_Url: parts[0],
            modelB_Url: parts[1],
            type: 'unknown'
          });
        }
      });
    }

    if (items.length === 0) {
      setError("Could not parse any valid pairs. Please check your format.");
      return;
    }

    onStart(items);
  };

  const loadSample = () => {
    setInputText(JSON.stringify(SAMPLE_DATA, null, 2));
    setError(null);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="text-center mb-10">
        <h1 className="text-4xl font-bold text-slate-800 mb-4 tracking-tight">Setup Evaluation</h1>
        <p className="text-slate-600 max-w-2xl mx-auto">
          Paste your dataset below. We support <strong>JSON</strong> (array of objects) or <strong>CSV</strong> (comma/tab separated URLs).
          Perfect for comparing Control (Column A) vs Treatment (Column B).
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
        <div className="p-6">
          <label className="block text-sm font-medium text-slate-700 mb-2">
            Data Input
          </label>
          <div className="relative">
            <textarea
              className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 font-mono text-sm resize-none transition-all"
              placeholder={`Example JSON:\n[\n  { "modelA": "url1", "modelB": "url2" },\n  ...\n]\n\nOR CSV:\nhttp://.../img1.png, http://.../img2.png`}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
          </div>

          <div className="flex justify-between items-center mt-3 text-sm text-slate-500">
            <button 
              onClick={loadSample}
              className="text-blue-600 hover:text-blue-700 font-medium hover:underline flex items-center gap-1"
            >
              <Info size={14} /> Load Sample Data
            </button>
            <span>Supported formats: JSON, CSV, TSV</span>
          </div>

          {error && (
            <div className="mt-4 p-4 bg-red-50 border border-red-100 rounded-lg flex items-start gap-3 text-red-700">
              <AlertTriangle className="w-5 h-5 shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          )}
        </div>

        <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-end">
          <button
            onClick={parseInput}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-semibold shadow-lg shadow-blue-600/20 transition-all transform hover:scale-[1.02] active:scale-[0.98]"
          >
            <Play size={18} />
            Start Evaluation
          </button>
        </div>
      </div>
    </div>
  );
};

export default SetupScreen;

import React, { useEffect, useCallback } from 'react';
import { ArrowLeft, ArrowRight, CheckCircle2, ChevronRight, Equal, ThumbsUp } from 'lucide-react';
import { EvaluationItem, VoteType } from '../types';
import MediaRenderer from './MediaRenderer';
import { KEYBOARD_SHORTCUTS } from '../constants';

interface VotingScreenProps {
  item: EvaluationItem;
  currentIndex: number;
  totalItems: number;
  onVote: (vote: VoteType) => void;
  onEnd: () => void;
}

const VotingScreen: React.FC<VotingScreenProps> = ({ 
  item, 
  currentIndex, 
  totalItems, 
  onVote,
  onEnd
}) => {
  const progress = ((currentIndex) / totalItems) * 100;

  const handleKeyPress = useCallback((event: KeyboardEvent) => {
    const key = event.key;
    if (KEYBOARD_SHORTCUTS.A.includes(key)) onVote('A');
    else if (KEYBOARD_SHORTCUTS.B.includes(key)) onVote('B');
    else if (KEYBOARD_SHORTCUTS.TIE.includes(key)) onVote('Tie');
  }, [onVote]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [handleKeyPress]);

  return (
    <div className="h-full flex flex-col">
      {/* Header / Progress */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-4">
          <h2 className="font-bold text-slate-800 text-lg">Batch Evaluation</h2>
          <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded-md text-xs font-mono">
             {currentIndex + 1} / {totalItems}
          </span>
        </div>

        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-6 text-xs text-slate-400 font-medium">
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">←</kbd> Vote Left</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">Enter</kbd> Tie</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">→</kbd> Vote Right</span>
          </div>
          <button 
            onClick={onEnd}
            className="text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors"
          >
            End Session
          </button>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-slate-100">
        <div 
          className="h-full bg-blue-600 transition-all duration-300 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      {/* Main Content Area */}
      <div className="flex-1 p-4 md:p-6 flex flex-col md:flex-row gap-4 md:gap-8 overflow-hidden">

        {/* Left Side (A) */}
        <div className="flex-1 flex flex-col min-h-0">
          <div className="flex-1 relative min-h-0">
            <MediaRenderer 
              url={item.modelA_Url} 
              label="Model A" 
              isActive={true} 
            />
          </div>
          <button
            onClick={() => onVote('A')}
            className="mt-4 w-full py-4 bg-white border-2 border-slate-200 hover:border-blue-500 hover:bg-blue-50 text-slate-700 hover:text-blue-700 rounded-xl font-bold flex items-center justify-center gap-2 transition-all group shadow-sm"
          >
            <ThumbsUp className="w-5 h-5 group-hover:-translate-y-0.5 transition-transform" />
            Vote Model A
          </button>
        </div>

        {/* Center Divider / VS */}
        <div className="hidden md:flex flex-col items-center justify-center gap-2">
          <div className="w-px h-full bg-slate-200 mb-2"></div>
          <div className="bg-slate-100 text-slate-400 font-black text-xl p-2 rounded-full border border-slate-200">VS</div>
          <button
            onClick={() => onVote('Tie')}
            className="my-2 p-3 rounded-full bg-white border border-slate-200 hover:bg-slate-100 hover:border-slate-300 text-slate-500 transition-all shadow-sm tooltip"
            title="Mark as Tie"
          >
            <Equal size={20} />
          </button>
          <div className="w-px h-full bg-slate-200 mt-2"></div>
        </div>

        {/* Mobile Tie Button */}
        <button
            onClick={() => onVote('Tie')}
            className="md:hidden w-full py-2 bg-slate-100 border border-slate-200 rounded-lg font-medium text-slate-600"
        >
          It's a Tie
        </button>

        {/* Right Side (B) */}
        <div className="flex-1 flex flex-col min-h-0">
          <div className="flex-1 relative min-h-0">
             <MediaRenderer 
               url={item.modelB_Url} 
               label="Model B" 
               isActive={true} 
            />
          </div>
          <button
            onClick={() => onVote('B')}
            className="mt-4 w-full py-4 bg-white border-2 border-slate-200 hover:border-blue-500 hover:bg-blue-50 text-slate-700 hover:text-blue-700 rounded-xl font-bold flex items-center justify-center gap-2 transition-all group shadow-sm"
          >
            <ThumbsUp className="w-5 h-5 group-hover:-translate-y-0.5 transition-transform" />
            Vote Model B
          </button>
        </div>

      </div>
    </div>
  );
};

export default VotingScreen;

import React from 'react';
import { Download, RotateCcw, Trophy, Check } from 'lucide-react';
import { VoteRecord, EvaluationItem, VotingStats } from '../types';

interface ResultsScreenProps {
  votes: VoteRecord[];
  items: EvaluationItem[];
  onReset: () => void;
}

const ResultsScreen: React.FC<ResultsScreenProps> = ({ votes, items, onReset }) => {
  // Calculate Stats
  const stats: VotingStats = votes.reduce(
    (acc, curr) => {
      acc.total++;
      if (curr.vote === 'A') acc.aCount++;
      else if (curr.vote === 'B') acc.bCount++;
      else acc.tieCount++;
      return acc;
    },
    { total: 0, aCount: 0, bCount: 0, tieCount: 0 }
  );

  const winner = stats.aCount > stats.bCount ? 'Model A' : stats.bCount > stats.aCount ? 'Model B' : 'Tie';
  const aPercent = stats.total ? Math.round((stats.aCount / stats.total) * 100) : 0;
  const bPercent = stats.total ? Math.round((stats.bCount / stats.total) * 100) : 0;
  const tiePercent = stats.total ? 100 - aPercent - bPercent : 0;

  const downloadCSV = () => {
    const headers = ['ItemID', 'ModelA_URL', 'ModelB_URL', 'Winner', 'Timestamp'];
    const rows = votes.map(v => {
      const item = items.find(i => i.id === v.itemId);
      return [
        v.itemId,
        item?.modelA_Url || '',
        item?.modelB_Url || '',
        v.vote,
        new Date(v.timestamp).toISOString()
      ].map(field => `"${field}"`).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `evaluation_results_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 animate-in zoom-in-95 duration-500">
      <div className="text-center mb-10">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-yellow-100 text-yellow-600 rounded-full mb-4 ring-8 ring-yellow-50">
          <Trophy size={32} />
        </div>
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Evaluation Complete</h1>
        <p className="text-slate-600">Here is how the models performed.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        {/* Stat Cards */}
        <div className={`p-6 rounded-2xl border-2 ${stats.aCount >= stats.bCount ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-100'} shadow-sm`}>
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1">Model A</h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.aCount}</div>
          <div className="w-full bg-white/50 h-2 rounded-full overflow-hidden">
            <div className="h-full bg-blue-500" style={{ width: `${aPercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{aPercent}% Win Rate</p>
        </div>

        <div className="p-6 rounded-2xl bg-white border border-slate-100 shadow-sm">
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1">Ties</h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.tieCount}</div>
          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
             <div className="h-full bg-slate-400" style={{ width: `${tiePercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{tiePercent}% Rate</p>
        </div>

        <div className={`p-6 rounded-2xl border-2 ${stats.bCount >= stats.aCount ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-100'} shadow-sm`}>
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1">Model B</h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.bCount}</div>
           <div className="w-full bg-white/50 h-2 rounded-full overflow-hidden">
            <div className="h-full bg-blue-500" style={{ width: `${bPercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{bPercent}% Win Rate</p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <h3 className="font-semibold text-slate-700">Detailed Breakdown</h3>
          <div className="flex gap-2">
             <button
              onClick={onReset}
              className="flex items-center gap-2 px-4 py-2 text-slate-600 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors font-medium text-sm"
            >
              <RotateCcw size={16} /> Start Over
            </button>
            <button
              onClick={downloadCSV}
              className="flex items-center gap-2 px-5 py-2 bg-slate-900 hover:bg-slate-800 text-white rounded-lg transition-colors font-medium text-sm shadow-md"
            >
              <Download size={16} /> Download CSV
            </button>
          </div>
        </div>
        <div className="max-h-64 overflow-y-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 sticky top-0">
              <tr>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">ID</th>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">Winner</th>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200 text-right">Time</th>
              </tr>
            </thead>
            <tbody>
              {votes.map((v, i) => (
                <tr key={i} className="border-b border-slate-100 hover:bg-slate-50">
                  <td className="p-4 text-sm text-slate-600 font-mono">{v.itemId}</td>
                  <td className="p-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                      ${v.vote === 'A' ? 'bg-blue-100 text-blue-800' : 
                        v.vote === 'B' ? 'bg-indigo-100 text-indigo-800' : 'bg-slate-100 text-slate-800'}`}>
                      {v.vote === 'Tie' ? 'Tie' : `Model ${v.vote}`}
                    </span>
                  </td>
                  <td className="p-4 text-sm text-slate-400 text-right">
                    {new Date(v.timestamp).toLocaleTimeString()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ResultsScreen;

import React, { useState } from 'react';
import { Layers, ChevronRight } from 'lucide-react';
import SetupScreen from './components/SetupScreen';
import VotingScreen from './components/VotingScreen';
import ResultsScreen from './components/ResultsScreen';
import { AppState, EvaluationItem, VoteRecord, VoteType } from './types';

export default function App() {
  const [appState, setAppState] = useState<AppState>('setup');
  const [items, setItems] = useState<EvaluationItem[]>([]);
  const [votes, setVotes] = useState<VoteRecord[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  const handleStart = (parsedItems: EvaluationItem[]) => {
    setItems(parsedItems);
    setAppState('voting');
    setCurrentIndex(0);
    setVotes([]);
  };

  const handleVote = (vote: VoteType) => {
    const currentItem = items[currentIndex];

    const newVote: VoteRecord = {
      itemId: currentItem.id,
      vote,
      timestamp: Date.now(),
    };

    setVotes(prev => [...prev, newVote]);

    if (currentIndex < items.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setAppState('results');
    }
  };

  const handleReset = () => {
    setAppState('setup');
    setItems([]);
    setVotes([]);
    setCurrentIndex(0);
  };

  const handleEndSessionEarly = () => {
    if (votes.length > 0) {
      setAppState('results');
    } else {
      handleReset();
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans selection:bg-blue-100">
      {/* Navbar */}
      <nav className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 sticky top-0 z-50">
        <div className="flex items-center gap-2 text-slate-800">
          <div className="bg-blue-600 text-white p-1.5 rounded-lg">
            <Layers size={20} />
          </div>
          <span className="font-bold text-lg tracking-tight">ModelEval Pro</span>
        </div>

        {/* Breadcrumbs */}
        <div className="hidden md:flex items-center gap-2 text-sm font-medium text-slate-400">
          <span className={appState === 'setup' ? 'text-blue-600' : ''}>Setup</span>
          <ChevronRight size={14} />
          <span className={appState === 'voting' ? 'text-blue-600' : ''}>Evaluate</span>
          <ChevronRight size={14} />
          <span className={appState === 'results' ? 'text-blue-600' : ''}>Results</span>
        </div>
      </nav>

      {/* Main Container */}
      <main className="h-[calc(100vh-64px)] overflow-auto">
        {appState === 'setup' && (
          <div className="h-full flex items-center justify-center">
            <SetupScreen onStart={handleStart} />
          </div>
        )}

        {appState === 'voting' && items.length > 0 && (
          <VotingScreen 
            item={items[currentIndex]}
            currentIndex={currentIndex}
            totalItems={items.length}
            onVote={handleVote}
            onEnd={handleEndSessionEarly}
          />
        )}

        {appState === 'results' && (
          <div className="h-full py-10">
            <ResultsScreen 
              votes={votes} 
              items={items}
              onReset={handleReset} 
            />
          </div>
        )}
      </main>
    </div>
  );
}

