import React, { useState } from 'react';
import { Upload, Play, Info, AlertTriangle, Download, Copy } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_DATA } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[]) => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ onStart }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState<string | null>(null);

  const parseInput = (text: string): EvaluationItem[] => {
    const items: EvaluationItem[] = [];

    // Try parsing as JSON
    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) {
        parsed.forEach((item, index) => {
          // Flexible key detection
          const urlA = item.modelA || item.urlA || item.control || item.a || item[0];
          const urlB = item.modelB || item.urlB || item.treatment || item.b || item[1];
          const prompt = item.prompt || item.text || item.caption || item.input;
          const refUrl = item.reference || item.ref || item.referenceUrl || item.start_frame || item.image;

          if (urlA && urlB) {
            items.push({
              id: `item-${index}`,
              modelA_Url: String(urlA),
              modelB_Url: String(urlB),
              prompt: prompt ? String(prompt) : undefined,
              referenceUrl: refUrl ? String(refUrl) : undefined,
              type: 'unknown'
            });
          }
        });
      }
    } catch (e) {
      // If JSON fails, try CSV/Line-based
      const lines = text.split('\n');
      lines.forEach((line, index) => {
        const parts = line.split(/[,\t]+/).map(s => s.trim()).filter(Boolean);
        if (parts.length >= 2) {
          items.push({
            id: `item-${index}`,
            modelA_Url: parts[0],
            modelB_Url: parts[1],
            type: 'unknown'
          });
        }
      });
    }
    return items;
  };

  const handleStart = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please enter some data first.");
      return;
    }

    const items = parseInput(inputText);

    if (items.length === 0) {
      setError("Could not parse any valid pairs. Please check your format.");
      return;
    }

    onStart(items);
  };

  const downloadConfig = () => {
    if (!inputText.trim()) return;
    try {
      // Re-parse to ensure valid JSON structure is downloaded even if CSV was input (best effort)
      const items = parseInput(inputText);
      if (items.length === 0) {
         setError("Nothing valid to export.");
         return;
      }

      // Convert back to a clean JSON format for sharing
      const exportData = items.map(item => ({
        prompt: item.prompt,
        reference: item.referenceUrl,
        modelA: item.modelA_Url,
        modelB: item.modelB_Url
      }));

      const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `eval_config_${new Date().toISOString().slice(0,10)}.json`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (e) {
      setError("Failed to export config.");
    }
  };

  const loadSample = () => {
    setInputText(JSON.stringify(SAMPLE_DATA, null, 2));
    setError(null);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="text-center mb-8">
        <h1 className="text-4xl font-bold text-slate-800 mb-4 tracking-tight">Setup Evaluation</h1>
        <p className="text-slate-600 max-w-2xl mx-auto">
          Paste your dataset below. To share this workload with colleagues, setup the data here, then click <strong>"Download Config"</strong> and send them the JSON file.
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
        <div className="p-6">
          <div className="flex justify-between items-center mb-2">
            <label className="text-sm font-medium text-slate-700">
              Data Input (JSON Array)
            </label>
            <div className="flex gap-2">
               <button 
                onClick={loadSample}
                className="text-blue-600 hover:text-blue-700 text-xs font-medium hover:underline flex items-center gap-1"
              >
                <Info size={12} /> Load Sample
              </button>
            </div>
          </div>

          <div className="relative">
            <textarea
              className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 font-mono text-sm resize-none transition-all"
              placeholder={`[\n  {\n    "prompt": "A cat...",\n    "reference": "http://img...",\n    "modelA": "http://video1...",\n    "modelB": "http://video2..."\n  }\n]`}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
          </div>

          {error && (
            <div className="mt-4 p-4 bg-red-50 border border-red-100 rounded-lg flex items-start gap-3 text-red-700">
              <AlertTriangle className="w-5 h-5 shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          )}
        </div>

        <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-between items-center">
          <button
            onClick={downloadConfig}
            className="flex items-center gap-2 text-slate-600 hover:text-slate-900 px-4 py-2 rounded-lg hover:bg-slate-200 transition-colors font-medium text-sm"
            title="Download this configuration to share with your team"
          >
            <Download size={16} />
            Download Config
          </button>

          <button
            onClick={handleStart}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-semibold shadow-lg shadow-blue-600/20 transition-all transform hover:scale-[1.02] active:scale-[0.98]"
          >
            <Play size={18} />
            Start Evaluation
          </button>
        </div>
      </div>
    </div>
  );
};

