import React, { useState } from 'react';
import { Play, Info, AlertTriangle, Download, FileSpreadsheet, Command } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_CSV } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[]) => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ onStart }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState<string | null>(null);

  const parseInput = (text: string): EvaluationItem[] => {
    const items: EvaluationItem[] = [];
    const lines = text.trim().split('\n');

    lines.forEach((line, index) => {
      if (!line.trim()) return;

      // Excel copy-paste uses Tabs (\t), CSV uses commas (,)
      // We prioritize Tab splitting as it's safer for prompts containing commas
      let parts = line.split('\t');
      if (parts.length < 2) {
        // Fallback to comma if no tabs found
        parts = line.split(','); 
      }

      parts = parts.map(p => p.trim()).filter(p => p !== '');

      // Skip empty lines or header lines (heuristic: if first col is "Prompt" or "Model")
      if (parts.length === 0) return;
      if (index === 0 && (parts[0].toLowerCase().includes('prompt') || parts[0].toLowerCase().includes('model'))) {
        return;
      }

      let item: EvaluationItem | null = null;

      // Smart Column Detection
      if (parts.length === 2) {
        // Format: [URL A] [URL B]
        item = {
          id: `row-${index}`,
          modelA_Url: parts[0],
          modelB_Url: parts[1],
          type: 'unknown'
        };
      } else if (parts.length === 3) {
        // Format: [Prompt] [URL A] [URL B]
        item = {
          id: `row-${index}`,
          prompt: parts[0],
          modelA_Url: parts[1],
          modelB_Url: parts[2],
          type: 'unknown'
        };
      } else if (parts.length >= 4) {
        // Format: [Prompt] [Reference] [URL A] [URL B]
        item = {
          id: `row-${index}`,
          prompt: parts[0],
          referenceUrl: parts[1],
          modelA_Url: parts[2],
          modelB_Url: parts[3],
          type: 'unknown'
        };
      }

      if (item && item.modelA_Url.startsWith('http')) {
        items.push(item);
      }
    });

    return items;
  };

  const handleStart = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please paste your data first.");
      return;
    }

    const items = parseInput(inputText);

    if (items.length === 0) {
      setError("Could not recognize valid links. Please ensure your Excel/CSV has valid URLs starting with http/https.");
      return;
    }

    onStart(items);
  };

  const downloadConfig = () => {
    if (!inputText.trim()) return;
    const blob = new Blob([inputText], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `eval_data_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const loadSample = () => {
    setInputText(SAMPLE_CSV);
    setError(null);
  };

  return (
    <div className="max-w-5xl mx-auto p-8 animate-in fade-in slide-in-from-bottom-4 duration-500 h-full flex flex-col justify-center">

      {/* Header Section */}
      <div className="text-center mb-10">
        <h1 className="text-3xl font-bold text-slate-900 mb-3 tracking-tight">New Evaluation Session</h1>
        <p className="text-slate-500 text-lg max-w-2xl mx-auto">
          Copy data from Excel or Google Sheets and paste it below.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input Area (Main Focus) */}
        <div className="lg:col-span-8 flex flex-col gap-4">
          <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden flex flex-col h-full transition-all focus-within:ring-4 focus-within:ring-blue-100 focus-within:border-blue-400">
            <div className="flex-1 relative min-h-[320px]">
              <textarea
                className="w-full h-full p-6 bg-white font-mono text-sm leading-relaxed resize-none focus:outline-none text-slate-700 placeholder:text-slate-300"
                placeholder={`Paste directly from Excel here...\n\nExample Row:\nA blue sky\thttps://ref.jpg\thttps://model-a.mp4\thttps://model-b.mp4`}
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                spellCheck={false}
              />
              {/* Floating Action Button for Sample */}
              {inputText.length === 0 && (
                <button 
                  onClick={loadSample}
                  className="absolute bottom-6 right-6 text-slate-400 hover:text-blue-600 text-xs font-medium flex items-center gap-1 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100 hover:border-blue-200 transition-all"
                >
                  <Info size={14} /> Try Example Data
                </button>
              )}
            </div>

            {error && (
              <div className="px-6 py-3 bg-red-50 border-t border-red-100 text-red-600 text-sm flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-between items-center">
              <button
                onClick={downloadConfig}
                className="text-slate-500 hover:text-slate-800 text-sm font-medium flex items-center gap-2 px-2 py-1 rounded transition-colors"
                title="Save current input to a file"
              >
                <Download size={16} />
                <span>Save Backup</span>
              </button>

              <button
                onClick={handleStart}
                disabled={!inputText.trim()}
                className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-semibold shadow-lg shadow-slate-900/10 transition-all transform hover:-translate-y-0.5 active:translate-y-0"
