import React, { useEffect, useCallback, useState } from 'react';
import { ArrowLeft, ArrowRight, CheckCircle2, ChevronDown, ChevronRight, ChevronUp, Cloud, Equal, Expand, ExternalLink, MessageSquare, ThumbsUp } from 'lucide-react';
import { EvaluationItem, VoteType } from '../types';
import MediaRenderer from './MediaRenderer';
import { KEYBOARD_SHORTCUTS } from '../constants';

interface VotingScreenProps {
  item: EvaluationItem;
  currentIndex: number;
  totalItems: number;
  onVote: (vote: VoteType) => void;
  onEnd: () => void;
}

const VotingScreen: React.FC<VotingScreenProps> = ({ 
  item, 
  currentIndex, 
  totalItems, 
  onVote,
  onEnd
}) => {
  const [showFullPrompt, setShowFullPrompt] = useState(false);
  const [showReference, setShowReference] = useState(false);
  const [justSaved, setJustSaved] = useState(false);
  const progress = ((currentIndex) / totalItems) * 100;

  const handleKeyPress = useCallback((event: KeyboardEvent) => {
    // Don't trigger if user is typing in a textarea (future proofing)
    if (event.target instanceof HTMLTextAreaElement || event.target instanceof HTMLInputElement) return;

    const key = event.key;
    if (KEYBOARD_SHORTCUTS.A.includes(key)) onVote('A');
    else if (KEYBOARD_SHORTCUTS.B.includes(key)) onVote('B');
    else if (KEYBOARD_SHORTCUTS.TIE.includes(key)) onVote('Tie');
  }, [onVote]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [handleKeyPress]);

  // Reset states on new item and show saved feedback
  useEffect(() => {
    setShowFullPrompt(false);
    setShowReference(false);

    // Trigger saved animation
    setJustSaved(true);
    const timer = setTimeout(() => setJustSaved(false), 2000);
    return () => clearTimeout(timer);
  }, [item.id]);

  return (
    <div className="h-full flex flex-col">
      {/* Header / Progress */}
      <div className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-4">
          <h2 className="font-bold text-slate-800 text-lg">Batch Evaluation</h2>
          <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded-md text-xs font-mono">
             {currentIndex + 1} / {totalItems}
          </span>

          {/* Saved Indicator */}
          <div className={`flex items-center gap-1 text-xs font-medium transition-all duration-500 ${justSaved ? 'text-green-600 opacity-100' : 'text-slate-300 opacity-50'}`}>
            {justSaved ? <CheckCircle2 size={14} /> : <Cloud size={14} />}
            <span>{justSaved ? 'Saved' : 'Auto-save on'}</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="hidden lg:flex items-center gap-6 text-xs text-slate-400 font-medium">
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">1</kbd> Vote Left</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">Enter</kbd> Tie</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">2</kbd> Vote Right</span>
          </div>
          <button 
            onClick={onEnd}
            className="text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors border-l border-slate-200 pl-4"
          >
            End Session
          </button>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-slate-100 shrink-0">
        <div 
          className="h-full bg-blue-600 transition-all duration-300 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      {/* Main Layout */}
      <div className="flex-1 flex flex-col overflow-hidden bg-slate-50">

        {/* Top Section: Prompt (Optional) */}
        {item.prompt && (
          <div className="bg-white border-b border-slate-200 px-6 py-3 shrink-0 relative shadow-sm z-10">
            <div 
              className={`text-slate-700 text-sm leading-relaxed transition-all duration-300 ${showFullPrompt ? '' : 'line-clamp-2 pr-8'}`}
            >
              <span className="font-semibold text-slate-900 mr-2 select-none uppercase text-xs tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">Prompt</span>
              {item.prompt}
            </div>
            {item.prompt.length > 150 && (
              <button 
                onClick={() => setShowFullPrompt(!showFullPrompt)}
                className="absolute right-4 top-3 text-slate-400 hover:text-blue-600 p-1"
              >
                {showFullPrompt ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
              </button>
            )}
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 p-4 md:p-6 flex gap-4 md:gap-6 min-h-0">

          {/* Left Side (A) */}
          <div className="flex-1 flex flex-col min-h-0 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden group/card hover:border-blue-300 transition-colors">
            <div className="flex-1 relative min-h-0 p-1 bg-slate-900">
              <MediaRenderer 
                url={item.modelA_Url} 
                label="Model A" 
                isActive={true} 
              />
            </div>
            <button
              onClick={() => onVote('A')}
              className="p-4 bg-white hover:bg-blue-50 text-slate-700 hover:text-blue-700 font-bold flex items-center justify-center gap-2 transition-all border-t border-slate-100"
            >
              <ThumbsUp className="w-5 h-5" />
              Vote Model A
            </button>
          </div>

          {/* Center Control Column */}
          <div className="flex flex-col items-center justify-center gap-4 w-16 shrink-0">

            {/* Reference Image Button/Thumbnail */}
            {item.referenceUrl && (
              <div className="relative group">
                <button 
                   onClick={() => setShowReference(true)}
                   className="w-16 h-16 rounded-xl border-2 border-slate-200 bg-white shadow-sm overflow-hidden hover:border-blue-500 transition-all flex items-center justify-center relative"
                >
                  <img src={item.referenceUrl} className="w-full h-full object-cover opacity-80 group-hover:opacity-100" />
                  <div className="absolute inset-0 bg-black/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <Expand size={16} className="text-white" />
                  </div>
                </button>
                <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-medium text-slate-400 whitespace-nowrap">Reference</div>
              </div>
            )}

            <div className="h-full w-px bg-slate-200 rounded-full my-2"></div>

            {/* Tie Button */}
            <button
              onClick={() => onVote('Tie')}
              className="w-12 h-12 rounded-full bg-white border-2 border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-500 hover:text-slate-800 transition-all shadow-sm flex items-center justify-center"
              title="Tie"
            >
              <Equal size={20} />
            </button>
            <span className="text-[10px] font-medium text-slate-400">Tie</span>

            <div className="h-full w-px bg-slate-200 rounded-full my-2"></div>

          </div>

          {/* Right Side (B) */}
           <div className="flex-1 flex flex-col min-h-0 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden group/card hover:border-indigo-300 transition-colors">
            <div className="flex-1 relative min-h-0 p-1 bg-slate-900">
             <MediaRenderer 
               url={item.modelB_Url} 
               label="Model B" 
               isActive={true} 
            />
            </div>
            <button
              onClick={() => onVote('B')}
              className="p-4 bg-white hover:bg-indigo-50 text-slate-700 hover:text-indigo-700 font-bold flex items-center justify-center gap-2 transition-all border-t border-slate-100"
            >
              <ThumbsUp className="w-5 h-5" />
              Vote Model B
            </button>
          </div>

        </div>
      </div>

      {/* Reference Image Modal/Overlay */}
      {showReference && item.referenceUrl && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setShowReference(false)}>
           <div className="relative max-w-4xl max-h-[90vh] bg-slate-900 rounded-xl overflow-hidden shadow-2xl p-1">
             <img src={item.referenceUrl} className="max-w-full max-h-[85vh] object-contain" />
             <div className="absolute top-4 left-4 bg-black/50 text-white px-3 py-1 rounded-full text-sm font-medium backdrop-blur-md">
               Reference Input
             </div>
             <button className="absolute top-4 right-4 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full backdrop-blur-md transition-colors">
               <Expand size={20} />
             </button>
           </div>
           <div className="absolute bottom-10 text-white/80 text-sm">Click anywhere to close</div>
        </div>
      )}
    </div>
  );
};

