export default SetupScreen;

import React, { useState, useEffect } from 'react';
import { Layers, ChevronRight } from 'lucide-react';
import SetupScreen from './components/SetupScreen';
import VotingScreen from './components/VotingScreen';
import ResultsScreen from './components/ResultsScreen';
import AnalysisScreen from './components/AnalysisScreen';
import { AppState, EvaluationItem, VoteRecord, VoteType } from './types';

const STORAGE_KEY = 'modeleval_session';

export default function App() {
  const [appState, setAppState] = useState<AppState>('setup');
  const [items, setItems] = useState<EvaluationItem[]>([]);
  const [votes, setVotes] = useState<VoteRecord[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [userName, setUserName] = useState('');
  const [modelNames, setModelNames] = useState({ a: 'Model A', b: 'Model B' });
  const [hasSavedSession, setHasSavedSession] = useState(false);

  // Check for saved session on load
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setHasSavedSession(true);
    }
  }, [appState]); // Check whenever appState changes (e.g. after reset)

  // Auto-save effect
  useEffect(() => {
    if (appState === 'voting' && items.length > 0) {
      const sessionData = {
        items,
        votes,
        currentIndex,
        userName,
        modelNames,
        timestamp: Date.now()
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(sessionData));
    } else if (appState === 'results') {
       // Keep it in results so they don't lose it on refresh, 
       // but maybe clear it if they explicitly hit "Reset"
    }
  }, [items, votes, currentIndex, appState, userName, modelNames]);

  const resumeSession = () => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setItems(data.items);
        setVotes(data.votes);
        setCurrentIndex(data.currentIndex);
        setUserName(data.userName || '');
        if (data.modelNames) setModelNames(data.modelNames);
        setAppState('voting');
      } catch (e) {
        console.error("Failed to parse saved session");
      }
    }
  };

  const discardSession = () => {
    if (confirm("Are you sure you want to discard your previous progress? This cannot be undone.")) {
      localStorage.removeItem(STORAGE_KEY);
      setHasSavedSession(false);
    }
  };

  const handleStart = (parsedItems: EvaluationItem[], name: string, parsedNames?: { a: string, b: string }) => {
    setItems(parsedItems);
    setUserName(name);
    if (parsedNames) setModelNames(parsedNames);
    else setModelNames({ a: 'Model A', b: 'Model B' });

    setAppState('voting');
    setCurrentIndex(0);
    setVotes([]);
  };

  const handleVote = (vote: VoteType) => {
    const currentItem = items[currentIndex];

    const newVote: VoteRecord = {
      itemId: currentItem.id,
      vote,
      timestamp: Date.now(),
      user: userName
    };

    setVotes(prev => [...prev, newVote]);

    if (currentIndex < items.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setAppState('results');
    }
  };

  const handleReset = () => {
    if (confirm("Are you sure? This will clear your current session data.")) {
      setAppState('setup');
      setItems([]);
      setVotes([]);
      setCurrentIndex(0);
      setModelNames({ a: 'Model A', b: 'Model B' });
      localStorage.removeItem(STORAGE_KEY);
      setHasSavedSession(false);
    }
  };

  const handleEndSessionEarly = () => {
    if (votes.length > 0) {
      setAppState('results');
    } else {
      handleReset();
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans selection:bg-blue-100">
      {/* Navbar */}
      <nav className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 sticky top-0 z-50">
        <div className="flex items-center gap-2 text-slate-800 cursor-pointer" onClick={() => appState !== 'voting' && setAppState('setup')}>
          <div className="bg-blue-600 text-white p-1.5 rounded-lg">
            <Layers size={20} />
          </div>
          <span className="font-bold text-lg tracking-tight">ModelEval Pro</span>
        </div>

        {/* Breadcrumbs */}
        <div className="hidden md:flex items-center gap-2 text-sm font-medium text-slate-400">
          <span className={appState === 'setup' || appState === 'analysis' ? 'text-blue-600' : ''}>Setup</span>
          <ChevronRight size={14} />
          <span className={appState === 'voting' ? 'text-blue-600' : ''}>Evaluate</span>
          <ChevronRight size={14} />
          <span className={appState === 'results' ? 'text-blue-600' : ''}>Results</span>
        </div>
      </nav>

      {/* Main Container */}
      <main className="h-[calc(100vh-64px)] overflow-auto">
        {appState === 'setup' && (
          <div className="h-full flex items-center justify-center">
            <SetupScreen 
              onStart={handleStart} 
              onGoToAnalysis={() => setAppState('analysis')}
              savedSession={hasSavedSession}
              onResume={resumeSession}
              onDiscardSession={discardSession}
            />
          </div>
        )}

        {appState === 'analysis' && (
          <div className="h-full py-10">
            <AnalysisScreen onBack={() => setAppState('setup')} />
          </div>
        )}

        {appState === 'voting' && items.length > 0 && (
          <VotingScreen 
            item={items[currentIndex]}
            currentIndex={currentIndex}
            totalItems={items.length}
            onVote={handleVote}
            onEnd={handleEndSessionEarly}
          />
        )}

        {appState === 'results' && (
          <div className="h-full py-10">
            <ResultsScreen 
              votes={votes} 
              items={items}
              onReset={handleReset} 
              userName={userName}
              modelNames={modelNames}
            />
          </div>
        )}
      </main>
    </div>
  );
}

import React from 'react';
import { Download, RotateCcw, Trophy, Check } from 'lucide-react';
import { VoteRecord, EvaluationItem, VotingStats } from '../types';

interface ResultsScreenProps {
  votes: VoteRecord[];
  items: EvaluationItem[];
  onReset: () => void;
  userName?: string;
  modelNames: { a: string; b: string };
}

const ResultsScreen: React.FC<ResultsScreenProps> = ({ votes, items, onReset, userName, modelNames }) => {
  // Calculate Stats
  const stats: VotingStats = votes.reduce(
    (acc, curr) => {
      acc.total++;
      if (curr.vote === 'A') acc.aCount++;
      else if (curr.vote === 'B') acc.bCount++;
      else acc.tieCount++;
      return acc;
    },
    { total: 0, aCount: 0, bCount: 0, tieCount: 0 }
  );

  const aPercent = stats.total ? Math.round((stats.aCount / stats.total) * 100) : 0;
  const bPercent = stats.total ? Math.round((stats.bCount / stats.total) * 100) : 0;
  const tiePercent = stats.total ? 100 - aPercent - bPercent : 0;

  const downloadCSV = () => {
    // Added Model Name columns at the end to preserve standard structure for Analysis tool
    // Standard cols: ItemID, ModelA_URL, ModelB_URL, Winner, Timestamp, User
    // New cols: ModelA_Name, ModelB_Name
    const headers = ['ItemID', 'ModelA_URL', 'ModelB_URL', 'Winner', 'Timestamp', 'User', 'ModelA_Name', 'ModelB_Name'];
    const rows = votes.map(v => {
      const item = items.find(i => i.id === v.itemId);
      return [
        v.itemId,
        item?.modelA_Url || '',
        item?.modelB_Url || '',
        v.vote,
        new Date(v.timestamp).toISOString(),
        userName || 'Anonymous',
        modelNames.a,
        modelNames.b
      ].map(field => `"${field}"`).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `results_${userName || 'anon'}_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 animate-in zoom-in-95 duration-500">
      <div className="text-center mb-10">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-yellow-100 text-yellow-600 rounded-full mb-4 ring-8 ring-yellow-50">
          <Trophy size={32} />
        </div>
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Evaluation Complete</h1>
        <p className="text-slate-600">Great job, {userName || 'Evaluator'}! Here is how the models performed.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        {/* Stat Cards */}
        <div className={`p-6 rounded-2xl border-2 ${stats.aCount >= stats.bCount ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-100'} shadow-sm`}>
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-blue-500"></span>
            {modelNames.a}
          </h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.aCount} <span className="text-sm font-normal text-slate-400">votes</span></div>
          <div className="w-full bg-white/50 h-2 rounded-full overflow-hidden">
            <div className="h-full bg-blue-500" style={{ width: `${aPercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{aPercent}% Win Rate</p>
        </div>

        <div className="p-6 rounded-2xl bg-white border border-slate-100 shadow-sm">
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1">Ties</h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.tieCount} <span className="text-sm font-normal text-slate-400">votes</span></div>
          <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
             <div className="h-full bg-slate-400" style={{ width: `${tiePercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{tiePercent}% Rate</p>
        </div>

        <div className={`p-6 rounded-2xl border-2 ${stats.bCount >= stats.aCount ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-100'} shadow-sm`}>
          <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-indigo-500"></span>
            {modelNames.b}
          </h3>
          <div className="text-4xl font-bold text-slate-800 mb-2">{stats.bCount} <span className="text-sm font-normal text-slate-400">votes</span></div>
           <div className="w-full bg-white/50 h-2 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-500" style={{ width: `${bPercent}%` }}></div>
          </div>
          <p className="text-xs text-slate-500 mt-2">{bPercent}% Win Rate</p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <h3 className="font-semibold text-slate-700">Detailed Breakdown</h3>
          <div className="flex gap-2">
             <button
              onClick={onReset}
              className="flex items-center gap-2 px-4 py-2 text-slate-600 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors font-medium text-sm"
            >
              <RotateCcw size={16} /> Start Over
            </button>
            <button
              onClick={downloadCSV}
              className="flex items-center gap-2 px-5 py-2 bg-slate-900 hover:bg-slate-800 text-white rounded-lg transition-colors font-medium text-sm shadow-md"
            >
              <Download size={16} /> Download CSV
            </button>
          </div>
        </div>
        <div className="max-h-64 overflow-y-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 sticky top-0">
              <tr>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">ID</th>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">Winner</th>
                <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200 text-right">Time</th>
              </tr>
            </thead>
            <tbody>
              {votes.map((v, i) => (
                <tr key={i} className="border-b border-slate-100 hover:bg-slate-50">
                  <td className="p-4 text-sm text-slate-600 font-mono">{v.itemId}</td>
                  <td className="p-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                      ${v.vote === 'A' ? 'bg-blue-100 text-blue-800' : 
                        v.vote === 'B' ? 'bg-indigo-100 text-indigo-800' : 'bg-slate-100 text-slate-800'}`}>
                      {v.vote === 'Tie' ? 'Tie' : v.vote === 'A' ? modelNames.a : modelNames.b}
                    </span>
                  </td>
                  <td className="p-4 text-sm text-slate-400 text-right">
                    {new Date(v.timestamp).toLocaleTimeString()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ResultsScreen;

import React, { useState } from 'react';
import { Upload, FileText, BarChart3, Users, AlertCircle } from 'lucide-react';
import { AggregatedResult } from '../types';

interface AnalysisScreenProps {
  onBack: () => void;
}

const AnalysisScreen: React.FC<AnalysisScreenProps> = ({ onBack }) => {
  const [aggregatedData, setAggregatedData] = useState<AggregatedResult[]>([]);
  const [totalFiles, setTotalFiles] = useState(0);
  const [uniqueVoters, setUniqueVoters] = useState<Set<string>>(new Set());

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setTotalFiles(files.length);
    const newAggregated: Record<string, AggregatedResult> = {};
    const voters = new Set<string>();

    let filesProcessed = 0;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        const lines = text.split('\n');

        // CSV Header check: ItemID, ModelA, ModelB, Winner, Timestamp, User
        // Index mapping might vary if CSV format changes, but we assume standard format from ResultsScreen

        lines.forEach((line, idx) => {
          if (idx === 0) return; // Skip Header
          // Handle quoted CSV fields simply
          const parts = line.split(',').map(p => p.replace(/^"|"$/g, '').trim());
          if (parts.length < 4) return;

          const itemId = parts[0];
          const winner = parts[3];
          const user = parts[5] || 'Anonymous'; // Column 5 might be User

          if (!itemId) return;

          voters.add(user);

          if (!newAggregated[itemId]) {
            newAggregated[itemId] = {
              itemId,
              votes: { A: 0, B: 0, Tie: 0 },
              voters: []
            };
          }

          if (winner === 'A') newAggregated[itemId].votes.A++;
          else if (winner === 'B') newAggregated[itemId].votes.B++;
          else if (winner === 'Tie') newAggregated[itemId].votes.Tie++;

          newAggregated[itemId].voters.push(user);
        });

        filesProcessed++;
        if (filesProcessed === files.length) {
          setAggregatedData(Object.values(newAggregated));
          setUniqueVoters(voters);
        }
      };
      reader.readAsText(file as Blob);
    });
  };

  // Calculate totals
  const totalVotes = aggregatedData.reduce((acc, curr) => acc + curr.votes.A + curr.votes.B + curr.votes.Tie, 0);
  const totalA = aggregatedData.reduce((acc, curr) => acc + curr.votes.A, 0);
  const totalB = aggregatedData.reduce((acc, curr) => acc + curr.votes.B, 0);
  const totalTie = aggregatedData.reduce((acc, curr) => acc + curr.votes.Tie, 0);

  const percentA = totalVotes ? Math.round((totalA / totalVotes) * 100) : 0;
  const percentB = totalVotes ? Math.round((totalB / totalVotes) * 100) : 0;

  return (
    <div className="max-w-6xl mx-auto p-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Team Analysis Dashboard</h1>
          <p className="text-slate-500">Upload multiple CSV result files to see aggregate statistics.</p>
        </div>
        <button 
          onClick={onBack}
          className="text-slate-500 hover:text-slate-800 font-medium text-sm"
        >
          Back to Setup
        </button>
      </div>

      {aggregatedData.length === 0 ? (
        <div className="bg-white border-2 border-dashed border-slate-300 rounded-2xl p-12 text-center hover:border-blue-400 transition-colors">
          <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <Upload size={32} />
          </div>
          <h3 className="text-xl font-semibold text-slate-800 mb-2">Upload Result CSVs</h3>
          <p className="text-slate-500 mb-6 max-w-md mx-auto">
            Select all the CSV files generated by your team members. We will merge them to calculate the final winner.
          </p>
          <label className="inline-flex cursor-pointer bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-semibold shadow-lg shadow-blue-600/20 transition-all transform hover:scale-105">
            <input type="file" multiple accept=".csv" className="hidden" onChange={handleFileUpload} />
            Select Files
          </label>
        </div>
      ) : (
        <div className="space-y-8">

          {/* Top Stats */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Participants</div>
              <div className="flex items-center gap-2 text-2xl font-bold text-slate-800">
                <Users className="text-purple-500" />
                {uniqueVoters.size}
              </div>
              <div className="text-xs text-slate-400 truncate mt-1">
                {Array.from(uniqueVoters).join(', ')}
              </div>
            </div>
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Total Judgements</div>
              <div className="flex items-center gap-2 text-2xl font-bold text-slate-800">
                <FileText className="text-blue-500" />
                {totalVotes}
              </div>
            </div>
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Model A Wins</div>
              <div className="flex items-center gap-2 text-2xl font-bold text-slate-800">
                <BarChart3 className="text-green-500" />
                {percentA}%
              </div>
            </div>
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
              <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Model B Wins</div>
              <div className="flex items-center gap-2 text-2xl font-bold text-slate-800">
                <BarChart3 className="text-indigo-500" />
                {percentB}%
              </div>
            </div>
          </div>

          {/* Breakdown Table */}
          <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-700">Item Consensus</h3>
              <label className="text-xs font-medium text-blue-600 cursor-pointer hover:underline">
                <input type="file" multiple accept=".csv" className="hidden" onChange={handleFileUpload} />
                + Add more files
              </label>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50">
                  <tr>
                    <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">Item ID</th>
                    <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200 w-1/3">Vote Distribution</th>
                    <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">Consensus</th>
                    <th className="p-4 text-xs font-semibold text-slate-500 uppercase border-b border-slate-200">Winner</th>
                  </tr>
                </thead>
                <tbody>
                  {aggregatedData.map((item, i) => {
                    const itemTotal = item.votes.A + item.votes.B + item.votes.Tie;
                    const itemWin = item.votes.A > item.votes.B ? 'A' : item.votes.B > item.votes.A ? 'B' : 'Tie';
                    const maxVotes = Math.max(item.votes.A, item.votes.B, item.votes.Tie);
                    const agreement = Math.round((maxVotes / itemTotal) * 100);

                    return (
                      <tr key={i} className="border-b border-slate-100 hover:bg-slate-50">
                        <td className="p-4 text-sm text-slate-600 font-mono">{item.itemId}</td>
                        <td className="p-4">
                          <div className="flex h-2 rounded-full overflow-hidden bg-slate-100 w-full max-w-[200px]">
                            <div className="bg-blue-500" style={{ width: `${(item.votes.A / itemTotal) * 100}%` }} title={`A: ${item.votes.A}`} />
                            <div className="bg-slate-400" style={{ width: `${(item.votes.Tie / itemTotal) * 100}%` }} title={`Tie: ${item.votes.Tie}`} />
                            <div className="bg-indigo-500" style={{ width: `${(item.votes.B / itemTotal) * 100}%` }} title={`B: ${item.votes.B}`} />
                          </div>
                          <div className="flex justify-between text-[10px] text-slate-400 mt-1 max-w-[200px]">
                            <span>A: {item.votes.A}</span>
                            <span>B: {item.votes.B}</span>
                          </div>
                        </td>
                        <td className="p-4">
                           <span className={`px-2 py-1 rounded text-xs font-medium ${agreement < 60 ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}`}>
                             {agreement}% Agreement
                           </span>
                        </td>
                        <td className="p-4 font-bold text-sm text-slate-700">Model {itemWin}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AnalysisScreen;

export interface EvaluationItem {
  id: string;
  modelA_Url: string; // Control or Model A
  modelB_Url: string; // Treatment or Model B
  prompt?: string;    // The prompt used to generate
  referenceUrls?: string[]; // Changed from single string to array
  type: 'image' | 'video' | 'unknown';
}

export type VoteType = 'A' | 'B' | 'Tie';

export interface VoteRecord {
  itemId: string;
  vote: VoteType;
  timestamp: number;
  user?: string; // Who voted
}

export type AppState = 'setup' | 'voting' | 'results' | 'analysis';

export interface VotingStats {
  total: number;
  aCount: number;
  bCount: number;
  tieCount: number;
}

// For the analysis screen
export interface AggregatedResult {
  itemId: string;
  prompt?: string;
  votes: {
    A: number;
    B: number;
    Tie: number;
  };
  voters: string[]; // List of people who voted on this
}

import React, { useState, useEffect } from 'react';
import { Play, Info, AlertTriangle, Download, FileSpreadsheet, Command, PieChart, User, RotateCcw, ArrowRight } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_CSV } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[], userName: string, modelNames?: { a: string, b: string }) => void;
  onGoToAnalysis: () => void;
  savedSession?: boolean;
  onResume?: () => void;
  onDiscardSession?: () => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ 
  onStart, 
  onGoToAnalysis, 
  savedSession, 
  onResume,
  onDiscardSession 
}) => {
  const [inputText, setInputText] = useState('');
  const [userName, setUserName] = useState('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Try to pre-fill name from local storage
    const savedName = localStorage.getItem('eval_username');
    if (savedName) setUserName(savedName);
  }, []);

  const isUrl = (str: string) => {
    return str.toLowerCase().startsWith('http') || str.toLowerCase().startsWith('www');
  };

  const parseInput = (text: string) => {
    const items: EvaluationItem[] = [];
    const lines = text.trim().split('\n');
    let modelNames = { a: 'Model A', b: 'Model B' };

    lines.forEach((line, index) => {
      if (!line.trim()) return;

      // Split by tab or comma, remove empty entries
      let parts = line.split('\t');
      if (parts.length < 2) parts = line.split(','); 
      parts = parts.map(p => p.trim()).filter(p => p !== '');

      if (parts.length < 2) return; // Need at least A and B

      // --- Header Parsing Logic ---
      if (index === 0) {
        // Heuristic: If none of the columns look like URLs, it's probably a header
        const hasUrl = parts.some(p => isUrl(p));
        if (!hasUrl) {
          // Assuming the last two columns are always the model names
          if (parts.length >= 2) {
             modelNames = { a: parts[parts.length - 2], b: parts[parts.length - 1] };
          }
          return; // Skip header line
        }
      }

      // --- Data Parsing Logic (Smart Column Detection) ---
      // We assume the strict structure: [Optional Prompt] -> [Optional Refs...] -> [Model A] -> [Model B]
      // 1. Pop the last two as models.
      // 2. Check the first item. If it's NOT a URL, it's a prompt.
      // 3. Anything else in the middle is a reference URL.

      const modelB_Url = parts.pop()!;
      const modelA_Url = parts.pop()!;

      let prompt = '';
      let referenceUrls: string[] = [];

      if (parts.length > 0) {
        // Check first remaining item
        if (!isUrl(parts[0])) {
          prompt = parts.shift()!; // Remove prompt from start
        }
        // Remaining parts are references
        referenceUrls = parts.filter(p => isUrl(p));
      }

      const item: EvaluationItem = {
        id: `row-${index}`,
        modelA_Url,
        modelB_Url,
        prompt: prompt || undefined,
        referenceUrls: referenceUrls.length > 0 ? referenceUrls : undefined,
        type: 'unknown'
      };

      if (item.modelA_Url && isUrl(item.modelA_Url)) {
        items.push(item);
      }
    });

    return { items, modelNames };
  };

  const handleStart = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please paste your data first.");
      return;
    }

    const { items, modelNames } = parseInput(inputText);

    if (items.length === 0) {
      setError("Could not recognize valid links. Check your format.");
      return;
    }

    // Default to 'Anonymous' if empty
    const finalName = userName.trim() || "Anonymous";

    // Save name for next time
    localStorage.setItem('eval_username', finalName);
    onStart(items, finalName, modelNames);
  };

  const downloadConfig = () => {
    if (!inputText.trim()) return;
    const blob = new Blob([inputText], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `eval_data_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const loadSample = () => {
    setInputText(SAMPLE_CSV);
    setError(null);
  };

  if (savedSession) {
    return (
      <div className="max-w-2xl mx-auto p-6 animate-in zoom-in-95 duration-300 flex flex-col items-center justify-center h-full">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 p-8 w-full text-center">
          <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <AlertTriangle size={40} />
          </div>

          <h2 className="text-2xl font-bold text-slate-800 mb-2">Unfinished Evaluation Found</h2>
          <p className="text-slate-500 mb-8">
            It looks like your browser refreshed or closed unexpectedly.<br/>
            We saved your progress. Would you like to continue where you left off?
          </p>

          <div className="flex flex-col gap-3">
            <button 
              onClick={onResume}
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-lg shadow-lg shadow-blue-200 transition-all flex items-center justify-center gap-2"
            >
              <Play size={24} fill="currentColor" />
              Resume Evaluation
            </button>

            <button 
              onClick={onDiscardSession}
              className="w-full py-3 bg-white hover:bg-slate-50 text-slate-500 hover:text-red-600 border border-slate-200 hover:border-red-200 rounded-xl font-medium transition-all flex items-center justify-center gap-2"
            >
              <RotateCcw size={18} />
              Discard and Start New
            </button>
          </div>
        </div>
        <p className="mt-8 text-slate-400 text-sm">Your progress is stored locally in your browser.</p>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto p-6 animate-in fade-in slide-in-from-bottom-4 duration-500 h-full flex flex-col justify-center">

      {/* Header Section */}
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-slate-900 mb-2 tracking-tight">New Evaluation Session</h1>
        <p className="text-slate-500 max-w-2xl mx-auto">
          Single player mode: Paste data and vote. <br/> Team mode: Collect CSV results from everyone and use the Dashboard.
        </p>

        <div className="flex justify-center gap-4 mt-6">
          <button 
            onClick={onGoToAnalysis}
            className="bg-indigo-50 hover:bg-indigo-100 text-indigo-700 px-4 py-2 rounded-lg font-medium text-sm flex items-center gap-2 transition-colors border border-indigo-200"
          >
            <PieChart size={16} /> Open Analysis Dashboard
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input Area */}
        <div className="lg:col-span-8 flex flex-col gap-4">
          <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden flex flex-col h-full transition-all">

            <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex items-center gap-4">
              <div className="flex items-center gap-2 text-slate-600 font-medium">
                <User size={18} />
                <span>Your Name <span className="text-slate-400 font-normal text-xs">(Optional)</span>:</span>
              </div>
              <input 
                type="text" 
                value={userName}
                onChange={(e) => setUserName(e.target.value)}
                placeholder="e.g. Alice (Default: Anonymous)"
                className="flex-1 px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="flex-1 relative min-h-[300px]">
              <textarea
                className="w-full h-full p-6 bg-white font-mono text-sm leading-relaxed resize-none focus:outline-none text-slate-700 placeholder:text-slate-300"
                placeholder={`Paste your data here (Tabs or Commas). The system is smart:\n\n1. Last 2 columns = Models\n2. First column (if text) = Prompt\n3. Anything in between = Reference Images\n\nExample:\nPrompt\tRef_Img1\tRef_Img2\tModel_A_Url\tModel_B_Url`}
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                spellCheck={false}
              />
              {inputText.length === 0 && (
                <button 
                  onClick={loadSample}
                  className="absolute bottom-6 right-6 text-slate-400 hover:text-blue-600 text-xs font-medium flex items-center gap-1 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100 hover:border-blue-200 transition-all"
                >
                  <Info size={14} /> Try Example Data
                </button>
              )}
            </div>

            {error && (
              <div className="px-6 py-3 bg-red-50 border-t border-red-100 text-red-600 text-sm flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-between items-center">
              <button
                onClick={downloadConfig}
                className="text-slate-500 hover:text-slate-800 text-sm font-medium flex items-center gap-2 px-2 py-1 rounded transition-colors"
              >
                <Download size={16} />
                <span>Backup Input</span>
              </button>

              <button
                onClick={handleStart}
                disabled={!inputText.trim()}
                className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-semibold shadow-lg shadow-slate-900/10 transition-all transform hover:-translate-y-0.5 active:translate-y-0"
              >
                <span>Start Evaluation</span>
                <ArrowRight size={18} />
              </button>
            </div>
          </div>
        </div>

        {/* Guide / Visual Helper */}
        <div className="lg:col-span-4 flex flex-col justify-center">
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
            <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <FileSpreadsheet className="text-green-600" size={20} />
              Supported Formats
            </h3>
            <div className="space-y-6">

              <div className="group">
                <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Scenario 1: Standard</div>
                <div className="flex gap-2 text-xs font-mono overflow-x-auto pb-2">
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap">Prompt</span>
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap text-slate-400">Reference?</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model A</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model B</span>
                </div>
              </div>

              <div className="group">
                <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Scenario 2: Multi-Reference</div>
                <div className="flex gap-2 text-xs font-mono overflow-x-auto pb-2">
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap">Prompt</span>
                  <span className="bg-green-50 border border-green-200 text-green-700 px-2 py-1 rounded whitespace-nowrap">Ref 1</span>
                  <span className="bg-green-50 border border-green-200 text-green-700 px-2 py-1 rounded whitespace-nowrap">Ref 2...</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model A</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model B</span>
                </div>
                <p className="text-[10px] text-slate-400 mt-1">We automatically detect any number of reference URLs between the Prompt and the Models.</p>
              </div>

            </div>
            <div className="mt-6 pt-4 border-t border-slate-100">
              <p className="text-xs text-slate-400 leading-relaxed">
                <Command size={12} className="inline mr-1"/>
                Tip: The last two columns are always treated as the Models to evaluate.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SetupScreen;

import React, { useEffect, useCallback, useState } from 'react';
import { CheckCircle2, ChevronDown, ChevronUp, Cloud, Equal, Expand, MessageSquare, ThumbsUp, Layers, ArrowLeft, ArrowRight } from 'lucide-react';
import { EvaluationItem, VoteType } from '../types';
import MediaRenderer from './MediaRenderer';
import { KEYBOARD_SHORTCUTS } from '../constants';

interface VotingScreenProps {
  item: EvaluationItem;
  currentIndex: number;
  totalItems: number;
  onVote: (vote: VoteType) => void;
  onEnd: () => void;
}

const VotingScreen: React.FC<VotingScreenProps> = ({ 
  item, 
  currentIndex, 
  totalItems, 
  onVote,
  onEnd
}) => {
  const [showFullPrompt, setShowFullPrompt] = useState(false);
  const [showReference, setShowReference] = useState(false);
  const [currentRefIndex, setCurrentRefIndex] = useState(0);
  const [justSaved, setJustSaved] = useState(false);
  const progress = ((currentIndex) / totalItems) * 100;

  // Handle keys for voting AND gallery navigation
  const handleKeyPress = useCallback((event: KeyboardEvent) => {
    // Don't trigger if user is typing
    if (event.target instanceof HTMLTextAreaElement || event.target instanceof HTMLInputElement) return;

    const key = event.key;

    // Gallery Controls (Only if Modal Open)
    if (showReference && item.referenceUrls && item.referenceUrls.length > 1) {
      if (key === 'ArrowLeft') {
        setCurrentRefIndex(prev => (prev === 0 ? item.referenceUrls!.length - 1 : prev - 1));
        event.stopPropagation();
        return;
      }
      if (key === 'ArrowRight') {
        setCurrentRefIndex(prev => (prev === item.referenceUrls!.length - 1 ? 0 : prev + 1));
        event.stopPropagation();
        return;
      }
      if (key === 'Escape') {
        setShowReference(false);
        return;
      }
    }

    // Voting Controls (Only if Modal Closed)
    if (!showReference) {
      if (KEYBOARD_SHORTCUTS.A.includes(key)) onVote('A');
      else if (KEYBOARD_SHORTCUTS.B.includes(key)) onVote('B');
      else if (KEYBOARD_SHORTCUTS.TIE.includes(key)) onVote('Tie');
    }
  }, [onVote, showReference, item.referenceUrls]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [handleKeyPress]);

  // Reset states on new item
  useEffect(() => {
    setShowFullPrompt(false);
    setShowReference(false);
    setCurrentRefIndex(0);

    // Trigger saved animation
    setJustSaved(true);
    const timer = setTimeout(() => setJustSaved(false), 2000);
    return () => clearTimeout(timer);
  }, [item.id]);

  const hasReferences = item.referenceUrls && item.referenceUrls.length > 0;

  return (
    <div className="h-full flex flex-col">
      {/* Header / Progress */}
      <div className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-4">
          <h2 className="font-bold text-slate-800 text-lg">Batch Evaluation</h2>
          <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded-md text-xs font-mono">
             {currentIndex + 1} / {totalItems}
          </span>

          <div className={`flex items-center gap-1 text-xs font-medium transition-all duration-500 ${justSaved ? 'text-green-600 opacity-100' : 'text-slate-300 opacity-50'}`}>
            {justSaved ? <CheckCircle2 size={14} /> : <Cloud size={14} />}
            <span>{justSaved ? 'Saved' : 'Auto-save on'}</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="hidden lg:flex items-center gap-6 text-xs text-slate-400 font-medium">
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">1</kbd> Vote Left</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">Enter</kbd> Tie</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">2</kbd> Vote Right</span>
          </div>
          <button 
            onClick={onEnd}
            className="text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors border-l border-slate-200 pl-4"
          >
            End Session
          </button>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-slate-100 shrink-0">
        <div 
          className="h-full bg-blue-600 transition-all duration-300 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      {/* Main Layout */}
      <div className="flex-1 flex flex-col overflow-hidden bg-slate-50">

        {/* Top Section: Prompt */}
        {item.prompt && (
          <div className="bg-white border-b border-slate-200 px-6 py-3 shrink-0 relative shadow-sm z-10">
            <div 
              className={`text-slate-700 text-sm leading-relaxed transition-all duration-300 ${showFullPrompt ? '' : 'line-clamp-2 pr-8'}`}
            >
              <span className="font-semibold text-slate-900 mr-2 select-none uppercase text-xs tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">Prompt</span>
              {item.prompt}
            </div>
            {item.prompt.length > 150 && (
              <button 
                onClick={() => setShowFullPrompt(!showFullPrompt)}
                className="absolute right-4 top-3 text-slate-400 hover:text-blue-600 p-1"
              >
                {showFullPrompt ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
              </button>
            )}
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 p-4 md:p-6 flex gap-4 md:gap-6 min-h-0">

          {/* Left Side (A) */}
          <div className="flex-1 flex flex-col min-h-0 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden group/card hover:border-blue-300 transition-colors">
            <div className="flex-1 relative min-h-0 p-1 bg-slate-900">
              <MediaRenderer 
                url={item.modelA_Url} 
                label="Model A" 
                isActive={true} 
              />
            </div>
            <button
              onClick={() => onVote('A')}
              className="p-4 bg-white hover:bg-blue-50 text-slate-700 hover:text-blue-700 font-bold flex items-center justify-center gap-2 transition-all border-t border-slate-100"
            >
              <ThumbsUp className="w-5 h-5" />
              Vote Model A
            </button>
          </div>

          {/* Center Control Column */}
          <div className="flex flex-col items-center justify-center gap-4 w-16 shrink-0">

            {/* Reference Image Button */}
            {hasReferences && (
              <div className="relative group">
                <button 
                   onClick={() => setShowReference(true)}
                   className="w-16 h-16 rounded-xl border-2 border-slate-200 bg-white shadow-sm overflow-hidden hover:border-blue-500 transition-all flex items-center justify-center relative"
                >
                  <img src={item.referenceUrls![0]} className="w-full h-full object-cover opacity-80 group-hover:opacity-100" />
                  <div className="absolute inset-0 bg-black/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <Expand size={16} className="text-white" />
                  </div>
                </button>
                <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-medium text-slate-400 whitespace-nowrap">
                  {item.referenceUrls!.length > 1 ? `${item.referenceUrls!.length} Refs` : 'Ref'}
                </div>
                {item.referenceUrls!.length > 1 && (
                   <div className="absolute -top-2 -right-2 bg-blue-600 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full border border-white">
                     {item.referenceUrls!.length}
                   </div>
                )}
              </div>
            )}

            {hasReferences && <div className="h-8 w-px bg-slate-200 rounded-full my-1"></div>}

            {/* Tie Button */}
            <button
              onClick={() => onVote('Tie')}
              className="w-12 h-12 rounded-full bg-white border-2 border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-500 hover:text-slate-800 transition-all shadow-sm flex items-center justify-center"
              title="Tie"
            >
              <Equal size={20} />
            </button>
            <span className="text-[10px] font-medium text-slate-400">Tie</span>

            <div className="h-8 w-px bg-slate-200 rounded-full my-1"></div>

          </div>

          {/* Right Side (B) */}
           <div className="flex-1 flex flex-col min-h-0 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden group/card hover:border-indigo-300 transition-colors">
            <div className="flex-1 relative min-h-0 p-1 bg-slate-900">
             <MediaRenderer 
               url={item.modelB_Url} 
               label="Model B" 
               isActive={true} 
            />
            </div>
            <button
              onClick={() => onVote('B')}
              className="p-4 bg-white hover:bg-indigo-50 text-slate-700 hover:text-indigo-700 font-bold flex items-center justify-center gap-2 transition-all border-t border-slate-100"
            >
              <ThumbsUp className="w-5 h-5" />
              Vote Model B
            </button>
          </div>

        </div>
      </div>

      {/* Reference Gallery Modal */}
      {showReference && hasReferences && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setShowReference(false)}>

           <div className="relative w-full max-w-5xl h-full flex flex-col items-center justify-center p-4" onClick={(e) => e.stopPropagation()}>

             {/* Main Image */}
             <div className="relative flex-1 flex items-center justify-center w-full min-h-0 mb-4">
                <img 
                  src={item.referenceUrls![currentRefIndex]} 
                  className="max-w-full max-h-[80vh] object-contain rounded-lg shadow-2xl border border-white/10" 
                />
             </div>

             {/* Controls / Info */}
             <div className="flex items-center gap-4 bg-black/50 backdrop-blur-md px-6 py-3 rounded-full border border-white/10">
               {item.referenceUrls!.length > 1 && (
                  <>
                    <button 
                      onClick={() => setCurrentRefIndex(prev => (prev === 0 ? item.referenceUrls!.length - 1 : prev - 1))}
                      className="p-2 hover:bg-white/20 rounded-full text-white transition-colors"
                    >
                      <ArrowLeft size={20} />
                    </button>
                    <span className="text-white font-mono text-sm mx-2">
                      {currentRefIndex + 1} / {item.referenceUrls!.length}
                    </span>
                    <button 
                      onClick={() => setCurrentRefIndex(prev => (prev === item.referenceUrls!.length - 1 ? 0 : prev + 1))}
                      className="p-2 hover:bg-white/20 rounded-full text-white transition-colors"
                    >
                      <ArrowRight size={20} />
                    </button>
                  </>
               )}
               {item.referenceUrls!.length === 1 && <span className="text-white text-sm font-medium">Reference Image</span>}
             </div>

             {/* Close Button */}
             <button 
               onClick={() => setShowReference(false)}
               className="absolute top-6 right-6 text-white/50 hover:text-white p-2 rounded-full hover:bg-white/10 transition-colors"
             >
               <span className="text-sm font-medium mr-2">Close</span>
               <kbd className="bg-white/20 px-1.5 rounded text-xs">Esc</kbd>
             </button>

           </div>
        </div>
      )}
    </div>
  );
};

export default VotingScreen;

import React from 'react';
import { Download, RotateCcw, Trophy, Check } from 'lucide-react';
import { VoteRecord, EvaluationItem, VotingStats } from '../types';

interface ResultsScreenProps {
  votes: VoteRecord[];
  items: EvaluationItem[];
  onReset: () => void;
  userName?: string;
  modelNames: { a: string; b: string };
}

const ResultsScreen: React.FC<ResultsScreenProps> = ({ votes, items, onReset, userName, modelNames }) => {
  // Calculate Stats
  const stats: VotingStats = votes.reduce(
    (acc, curr) => {
      acc.total++;
      if (curr.vote === 'A') acc.aCount++;
      else if (curr.vote === 'B') acc.bCount++;
      else acc.tieCount++;
      return acc;
    },
    { total: 0, aCount: 0, bCount: 0, tieCount: 0 }
  );

  const aPercent = stats.total ? Math.round((stats.aCount / stats.total) * 100) : 0;
  const bPercent = stats.total ? Math.round((stats.bCount / stats.total) * 100) : 0;
  const tiePercent = stats.total ? 100 - aPercent - bPercent : 0;

  const downloadCSV = () => {
    // Standard cols: ItemID, ModelA_URL, ModelB_URL, Winner, Timestamp, User, ModelA_Name, ModelB_Name, References
    const headers = ['ItemID', 'ModelA_URL', 'ModelB_URL', 'Winner', 'Timestamp', 'User', 'ModelA_Name', 'ModelB_Name', 'References'];
    const rows = votes.map(v => {
      const item = items.find(i => i.id === v.itemId);
      return [
        v.itemId,
        item?.modelA_Url || '',
        item?.modelB_Url || '',
        v.vote,
        new Date(v.timestamp).toISOString(),
        userName || 'Anonymous',
        modelNames.a,
        modelNames.b,
        item?.referenceUrls ? item.referenceUrls.join(' | ') : ''
      ].map(field => `"${field}"`).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `results_${userName || 'anon'}_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 animate-in zoom-in-95 duration-500">
      <div className="text-center mb-10">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-yellow-100 text-yellow-600 rounded-full mb-4 ring-8 ring-yellow-50">
