import React, { useState, useEffect } from 'react';
import { Play, Info, AlertTriangle, Download, FileSpreadsheet, Command, PieChart, User, RotateCcw, ArrowRight } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_CSV } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[], userName: string, modelNames?: { a: string, b: string }) => void;
  onGoToAnalysis: () => void;
  savedSession?: boolean;
  onResume?: () => void;
  onDiscardSession?: () => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ 
  onStart, 
  onGoToAnalysis, 
  savedSession, 
  onResume,
  onDiscardSession 
}) => {
  const [inputText, setInputText] = useState('');
  const [userName, setUserName] = useState('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Try to pre-fill name from local storage
    const savedName = localStorage.getItem('eval_username');
    if (savedName) setUserName(savedName);
  }, []);

  const isUrl = (str: string) => {
    if (!str) return false;
    const s = str.trim().toLowerCase();
    return s.startsWith('http://') || s.startsWith('https://') || s.startsWith('www.');
  };

  /**
   * Robust CSV/Line parser.
   * Handles:
   * 1. TSV (Tab separated) - common from Excel copy-paste
   * 2. CSV (Comma separated) - standard, respects "quoted, strings"
   */
  const parseLine = (line: string): string[] => {
    // 1. Try Tab Separation first (Excel default)
    if (line.includes('\t')) {
      return line.split('\t').map(cleanCell);
    }

    // 2. CSV Parser respecting quotes
    const result: string[] = [];
    let current = '';
    let inQuote = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];

      if (char === '"') {
        // Toggle quote state. Handle escaped quotes ("") later in cleanup if needed, 
        // but for splitting, we just need to know if we are inside a text block.
        // Look ahead for escaped quote
        if (inQuote && line[i+1] === '"') {
             current += '"';
             i++; // Skip next quote
        } else {
             inQuote = !inQuote;
        }
      } else if (char === ',' && !inQuote) {
        result.push(cleanCell(current));
        current = '';
      } else {
        current += char;
      }
    }
    result.push(cleanCell(current));
    return result;
  };

  /**
   * Cleans cell data: removes surrounding quotes, unescapes double quotes
   */
  const cleanCell = (cell: string): string => {
    let content = cell.trim();
    // Remove wrapping quotes if they exist and match
    if (content.startsWith('"') && content.endsWith('"') && content.length > 1) {
      content = content.slice(1, -1);
    }
    // Excel CSV escapes double quotes as "" -> replace with "
    content = content.replace(/""/g, '"');
    return content;
  };

  const parseInput = (text: string) => {
    const items: EvaluationItem[] = [];
    const lines = text.trim().split('\n');
    let modelNames = { a: 'Model A', b: 'Model B' };

    lines.forEach((line, index) => {
      if (!line.trim()) return;

      const parts = parseLine(line).filter(p => p !== '');

      if (parts.length < 2) return; // Need at least A and B

      // --- Header Parsing Logic ---
      if (index === 0) {
        // Heuristic: If none of the columns look like URLs, it's probably a header
        const hasUrl = parts.some(p => isUrl(p));
        if (!hasUrl) {
          if (parts.length >= 2) {
             modelNames = { a: parts[parts.length - 2], b: parts[parts.length - 1] };
          }
          return; // Skip header line
        }
      }

      // --- Data Parsing Logic (Right-to-Left Strategy) ---
      // We assume:
      // [Prompt Parts...] [Optional References...] [Model A] [Model B]

      // 1. Pop Models
      const modelB_Url = parts.pop()!;
      const modelA_Url = parts.pop()!;

      let prompt = '';
      let referenceUrls: string[] = [];

      // 2. Process remaining parts from Right to Left
      // Everything strictly immediately to the left of models that IS a URL is a Reference.
      // Once we hit a non-URL (or run out), everything remaining to the left is Prompt.

      let processingRefs = true;
      const reversedRemaining = [...parts].reverse();
      const promptPartsReversed: string[] = [];

      for (const part of reversedRemaining) {
        if (processingRefs && isUrl(part)) {
          // It's a reference image
          referenceUrls.unshift(part); // Add to front to maintain order
        } else {
          // We hit a non-URL. Stop ref processing. This is part of the prompt.
          processingRefs = false;
          promptPartsReversed.push(part);
        }
      }

      // Reassemble prompt (Un-reverse)
      prompt = promptPartsReversed.reverse().join(' '); 

      // Final sanity check: if prompt is empty and we have refs, maybe the first ref was actually the prompt?
      // (Rare edge case where prompt is a URL, but we'll assume the user put prompt first)

      const item: EvaluationItem = {
        id: `row-${index}`,
        modelA_Url,
        modelB_Url,
        prompt: prompt || undefined,
        referenceUrls: referenceUrls.length > 0 ? referenceUrls : undefined,
        type: 'unknown'
      };

      if (item.modelA_Url && isUrl(item.modelA_Url)) {
        items.push(item);
      }
    });

    return { items, modelNames };
  };

  const handleStart = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please paste your data first.");
      return;
    }

    const { items, modelNames } = parseInput(inputText);

    if (items.length === 0) {
      setError("Could not recognize valid links. Check your format.");
      return;
    }

    // Default to 'Anonymous' if empty
    const finalName = userName.trim() || "Anonymous";

    // Save name for next time
    localStorage.setItem('eval_username', finalName);
    onStart(items, finalName, modelNames);
  };

