import React, { useEffect, useCallback, useState } from 'react';
import { CheckCircle2, ChevronDown, ChevronUp, Cloud, Equal, Expand, MessageSquare, ThumbsUp, Layers, ArrowLeft, ArrowRight, Shuffle } from 'lucide-react';
import { EvaluationItem, VoteType } from '../types';
import MediaRenderer from './MediaRenderer';
import { KEYBOARD_SHORTCUTS } from '../constants';

interface VotingScreenProps {
  item: EvaluationItem;
  currentIndex: number;
  totalItems: number;
  onVote: (vote: VoteType) => void;
  onEnd: () => void;
}

const VotingScreen: React.FC<VotingScreenProps> = ({ 
  item, 
  currentIndex, 
  totalItems, 
  onVote,
  onEnd
}) => {
  const [showFullPrompt, setShowFullPrompt] = useState(false);
  const [showReference, setShowReference] = useState(false);
  const [currentRefIndex, setCurrentRefIndex] = useState(0);
  const [justSaved, setJustSaved] = useState(false);
  const progress = ((currentIndex) / totalItems) * 100;

  // --- Blind Testing Logic ---
  // If isSwapped is true:
  // Left Screen shows Model B data
  // Right Screen shows Model A data
  const isSwapped = item.isSwapped ?? false;

  const leftData = isSwapped 
    ? { url: item.modelB_Url, voteVal: 'B' as VoteType } 
    : { url: item.modelA_Url, voteVal: 'A' as VoteType };

  const rightData = isSwapped 
    ? { url: item.modelA_Url, voteVal: 'A' as VoteType } 
    : { url: item.modelB_Url, voteVal: 'B' as VoteType };

  // Handle keys for voting AND gallery navigation
  const handleKeyPress = useCallback((event: KeyboardEvent) => {
    // Don't trigger if user is typing
    if (event.target instanceof HTMLTextAreaElement || event.target instanceof HTMLInputElement) return;

    const key = event.key;

    // Gallery Controls (Only if Modal Open)
    if (showReference && item.referenceUrls && item.referenceUrls.length > 1) {
      if (key === 'ArrowLeft') {
        setCurrentRefIndex(prev => (prev === 0 ? item.referenceUrls!.length - 1 : prev - 1));
        event.stopPropagation();
        return;
      }
      if (key === 'ArrowRight') {
        setCurrentRefIndex(prev => (prev === item.referenceUrls!.length - 1 ? 0 : prev + 1));
        event.stopPropagation();
        return;
      }
      if (key === 'Escape') {
        setShowReference(false);
        return;
      }
    }

    // Voting Controls (Only if Modal Closed)
    if (!showReference) {
      // Key A/Left -> Vote for Left Content (which might be Model A or B depending on swap)
      if (KEYBOARD_SHORTCUTS.A.includes(key)) onVote(leftData.voteVal);
      // Key B/Right -> Vote for Right Content
      else if (KEYBOARD_SHORTCUTS.B.includes(key)) onVote(rightData.voteVal);
      // Tie is always Tie
      else if (KEYBOARD_SHORTCUTS.TIE.includes(key)) onVote('Tie');
    }
  }, [onVote, showReference, item.referenceUrls, leftData.voteVal, rightData.voteVal]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [handleKeyPress]);

  // Reset states on new item
  useEffect(() => {
    setShowFullPrompt(false);
    setShowReference(false);
    setCurrentRefIndex(0);

    // Trigger saved animation
    setJustSaved(true);
    const timer = setTimeout(() => setJustSaved(false), 2000);
    return () => clearTimeout(timer);
  }, [item.id]);

  const hasReferences = item.referenceUrls && item.referenceUrls.length > 0;

  return (
    <div className="h-full flex flex-col">
      {/* Header / Progress */}
      <div className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-4">
          <h2 className="font-bold text-slate-800 text-lg">Batch Evaluation</h2>
          <span className="px-2 py-1 bg-slate-100 text-slate-500 rounded-md text-xs font-mono">
             {currentIndex + 1} / {totalItems}
          </span>

          <div className={`flex items-center gap-1 text-xs font-medium transition-all duration-500 ${justSaved ? 'text-green-600 opacity-100' : 'text-slate-300 opacity-50'}`}>
            {justSaved ? <CheckCircle2 size={14} /> : <Cloud size={14} />}
            <span>{justSaved ? 'Saved' : 'Auto-save on'}</span>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="hidden lg:flex items-center gap-6 text-xs text-slate-400 font-medium">
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">1</kbd> Vote Left</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">Enter</kbd> Tie</span>
            <span className="flex items-center gap-1"><kbd className="bg-slate-100 border border-slate-300 rounded px-1.5 py-0.5 text-slate-600">2</kbd> Vote Right</span>
          </div>
          <button 
            onClick={onEnd}
            className="text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors border-l border-slate-200 pl-4"
          >
            End Session
          </button>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-slate-100 shrink-0">
        <div 
          className="h-full bg-blue-600 transition-all duration-300 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      {/* Main Layout */}
      <div className="flex-1 flex flex-col overflow-hidden bg-slate-50">

        {/* Top Section: Prompt */}
        {item.prompt && (
          <div className="bg-white border-b border-slate-200 px-6 py-3 shrink-0 relative shadow-sm z-10">
            <div 
              className={`text-slate-700 text-sm leading-relaxed transition-all duration-300 ${showFullPrompt ? '' : 'line-clamp-2 pr-8'}`}
            >
              <span className="font-semibold text-slate-900 mr-2 select-none uppercase text-xs tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">Prompt</span>
              {item.prompt}
            </div>
            {item.prompt.length > 150 && (
              <button 
                onClick={() => setShowFullPrompt(!showFullPrompt)}
                className="absolute right-4 top-3 text-slate-400 hover:text-blue-600 p-1"
              >
                {showFullPrompt ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
              </button>
            )}
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 p-4 md:p-6 flex gap-4 md:gap-6 min-h-0">

          {/* Left Side (A or B if swapped) */}
