import React from 'react';
import { Download, Trash2, Calendar, User, ArrowLeft, BarChart3 } from 'lucide-react';
import { HistorySession, VotingStats } from '../types';

interface HistoryScreenProps {
  history: HistorySession[];
  onBack: () => void;
  onClearHistory: () => void;
  onDeleteSession: (id: string) => void;
}

const HistoryScreen: React.FC<HistoryScreenProps> = ({ history, onBack, onClearHistory, onDeleteSession }) => {

  const calculateStats = (votes: any[]): VotingStats => {
    return votes.reduce(
      (acc, curr) => {
        acc.total++;
        if (curr.vote === 'A') acc.aCount++;
        else if (curr.vote === 'B') acc.bCount++;
        else acc.tieCount++;
        return acc;
      },
      { total: 0, aCount: 0, bCount: 0, tieCount: 0 }
    );
  };

  const downloadCSV = (session: HistorySession) => {
    const headers = ['ItemID', 'ModelA_URL', 'ModelB_URL', 'Winner', 'Timestamp', 'User', 'ModelA_Name', 'ModelB_Name', 'References'];
    const rows = session.votes.map(v => {
      const item = session.items.find(i => i.id === v.itemId);
      return [
        v.itemId,
        item?.modelA_Url || '',
        item?.modelB_Url || '',
        v.vote,
        new Date(v.timestamp).toISOString(),
        session.userName || 'Anonymous',
        session.modelNames.a,
        session.modelNames.b,
        item?.referenceUrls ? item.referenceUrls.join(' | ') : ''
      ].map(field => `"${field}"`).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `results_${session.userName || 'anon'}_${new Date(session.timestamp).toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-5xl mx-auto p-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Evaluation History</h1>
          <p className="text-slate-500">View and download results from your past sessions.</p>
        </div>
        <div className="flex gap-4">
           {history.length > 0 && (
            <button 
              onClick={onClearHistory}
              className="text-red-500 hover:text-red-700 font-medium text-sm flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-red-50 transition-colors"
            >
              <Trash2 size={16} /> Clear All
            </button>
          )}
          <button 
            onClick={onBack}
            className="flex items-center gap-2 text-slate-600 hover:text-slate-900 font-medium text-sm px-4 py-2 bg-white border border-slate-200 rounded-lg shadow-sm hover:bg-slate-50"
          >
            <ArrowLeft size={16} /> Back
          </button>
        </div>
      </div>

      {history.length === 0 ? (
        <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-16 text-center">
          <div className="w-16 h-16 bg-slate-50 text-slate-400 rounded-full flex items-center justify-center mx-auto mb-4">
            <Calendar size={32} />
          </div>
          <h3 className="text-xl font-semibold text-slate-800 mb-2">No History Yet</h3>
          <p className="text-slate-500">Completed evaluations will appear here automatically.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {history.sort((a, b) => b.timestamp - a.timestamp).map((session) => {
            const stats = calculateStats(session.votes);
            const aPercent = stats.total ? Math.round((stats.aCount / stats.total) * 100) : 0;
            const bPercent = stats.total ? Math.round((stats.bCount / stats.total) * 100) : 0;
            const tiePercent = stats.total ? 100 - aPercent - bPercent : 0;

            return (
              <div key={session.id} className="bg-white rounded-xl border border-slate-200 shadow-sm p-6 hover:shadow-md transition-shadow">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">

                  {/* Meta Info */}
                  <div className="flex-1">
                    <div className="flex items-center gap-3 text-sm text-slate-500 mb-2">
                      <span className="flex items-center gap-1"><Calendar size={14} /> {new Date(session.timestamp).toLocaleDateString()} {new Date(session.timestamp).toLocaleTimeString()}</span>
                      <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                      <span className="flex items-center gap-1"><User size={14} /> {session.userName}</span>
                    </div>
                    <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                      <span className="text-blue-600">{session.modelNames.a}</span>
                      <span className="text-slate-300">vs</span>
                      <span className="text-indigo-600">{session.modelNames.b}</span>
                    </div>
                    <div className="text-sm text-slate-500 mt-1">
                      {session.items.length} items evaluated
                    </div>
                  </div>

                  {/* Mini Charts */}
                  <div className="flex-1 min-w-[200px]">
                    <div className="flex items-center justify-between text-xs font-medium text-slate-500 mb-1">
                      <span>Win Rate Distribution</span>
                    </div>
                    <div className="h-4 rounded-full overflow-hidden flex w-full bg-slate-100">
                      <div style={{ width: `${aPercent}%` }} className="bg-blue-500 h-full" title={`${session.modelNames.a}: ${aPercent}%`} />
                      <div style={{ width: `${tiePercent}%` }} className="bg-slate-300 h-full" title={`Tie: ${tiePercent}%`} />
                      <div style={{ width: `${bPercent}%` }} className="bg-indigo-500 h-full" title={`${session.modelNames.b}: ${bPercent}%`} />
                    </div>
                    <div className="flex justify-between text-xs mt-1 text-slate-400">
                      <span>A: {aPercent}%</span>
                      <span>Tie: {tiePercent}%</span>
                      <span>B: {bPercent}%</span>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex items-center gap-3 border-t md:border-t-0 md:border-l border-slate-100 pt-4 md:pt-0 md:pl-6">
                    <button 
                      onClick={() => downloadCSV(session)}
                      className="flex items-center gap-2 px-4 py-2 bg-slate-900 hover:bg-slate-800 text-white rounded-lg text-sm font-medium transition-colors whitespace-nowrap"
                    >
                      <Download size={16} /> CSV
                    </button>
                    <button 
                      onClick={() => onDeleteSession(session.id)}
                      className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      title="Delete Entry"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>

                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

