import React, { useState, useEffect } from 'react';
import { Play, Info, AlertTriangle, Download, FileSpreadsheet, Command, PieChart, User, RotateCcw, ArrowRight, History } from 'lucide-react';
import { EvaluationItem } from '../types';
import { SAMPLE_CSV } from '../constants';

interface SetupScreenProps {
  onStart: (items: EvaluationItem[], userName: string, modelNames?: { a: string, b: string }) => void;
  onGoToAnalysis: () => void;
  onGoToHistory: () => void;
  savedSession?: boolean;
  onResume?: () => void;
  onDiscardSession?: () => void;
}

const SetupScreen: React.FC<SetupScreenProps> = ({ 
  onStart, 
  onGoToAnalysis, 
  onGoToHistory,
  savedSession, 
  onResume,
  onDiscardSession 
}) => {
  const [inputText, setInputText] = useState('');
  const [userName, setUserName] = useState('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Try to pre-fill name from local storage
    const savedName = localStorage.getItem('eval_username');
    if (savedName) setUserName(savedName);
  }, []);

  const isUrl = (str: string) => {
    if (!str) return false;
    const s = str.trim().toLowerCase();
    // Looser URL check to catch edge cases, but strict enough for logic
    return s.startsWith('http://') || s.startsWith('https://') || s.startsWith('www.');
  };

  /**
   * Advanced State-Machine Parser
   * Parses the entire text block at once instead of splitting by line first.
   * This allows it to handle "Multiline Cells" correctly (e.g. Prompts with newlines wrapped in quotes).
   */
  const parseRawTextToRows = (text: string): string[][] => {
    if (!text) return [];

    // 1. Auto-detect delimiter
    // Look at the first 1000 chars to guess if it's Tab or Comma separated
    const sample = text.slice(0, 1000);
    const tabCount = (sample.match(/\t/g) || []).length;
    const commaCount = (sample.match(/,/g) || []).length;

    // Default to Tab (common for Excel copy/paste), unless Commas are significantly more frequent
    const delimiter = commaCount > tabCount ? ',' : '\t';

    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentCell = '';
    let inQuotes = false;

    for (let i = 0; i < text.length; i++) {
      const char = text[i];
      const nextChar = text[i + 1];

      // Handle Quotes
      if (char === '"') {
        if (inQuotes && nextChar === '"') {
          // Escaped quote ("") -> becomes a single literal quote
          currentCell += '"';
          i++; // Skip the next quote
        } else {
          // Toggle quote state
          inQuotes = !inQuotes;
        }
      } 
      // Handle Delimiter (Tab or Comma) - Only if NOT in quotes
      else if (char === delimiter && !inQuotes) {
        currentRow.push(currentCell.trim()); // Trim whitespace around cell content
        currentCell = '';
      } 
      // Handle Newlines (End of Row) - Only if NOT in quotes
      else if ((char === '\n' || char === '\r') && !inQuotes) {
        // Handle CRLF (\r\n) by skipping the \n if we just hit \r
        if (char === '\r' && nextChar === '\n') i++;

        currentRow.push(currentCell.trim());

        // Push the completed row if it's not empty
        if (currentRow.length > 0 && currentRow.some(c => c !== '')) {
          rows.push(currentRow);
        }

        // Reset for next row
        currentRow = [];
        currentCell = '';
      } 
      // Normal Character
      else {
        currentCell += char;
      }
    }

    // Flush the final cell/row if exists
    if (currentCell || currentRow.length > 0) {
      currentRow.push(currentCell.trim());
      if (currentRow.some(c => c !== '')) {
        rows.push(currentRow);
      }
    }

    return rows;
  };

  const parseInput = (text: string) => {
    const items: EvaluationItem[] = [];
    // Use the robust parser
    const rows = parseRawTextToRows(text);
    let modelNames = { a: 'Model A', b: 'Model B' };

    rows.forEach((parts, index) => {
      if (parts.length < 2) return; 

      // --- Header Parsing Logic ---
      if (index === 0) {
        const hasUrl = parts.some(p => isUrl(p));
        if (!hasUrl) {
          // If first row has no URLs, it's likely a header.
          // Grab the last two non-empty columns as model names
          if (parts.length >= 2) {
             modelNames = { a: parts[parts.length - 2], b: parts[parts.length - 1] };
          }
          return; // Skip header row
        }
      }

      // --- Data Parsing Logic (Right-to-Left Strategy) ---
      // [Prompt...] [Ref...] [Ref...] [Model A] [Model B]

      // 1. Pop Models (Last 2 columns)
      const modelB_Url = parts.pop()!;
      const modelA_Url = parts.pop()!;

      // 2. Scan remaining columns from Right -> Left for Reference URLs
      let promptParts: string[] = [];
      let referenceUrls: string[] = [];
      let scanningRefs = true;

      // Iterate remaining parts in reverse
      for (let i = parts.length - 1; i >= 0; i--) {
        const part = parts[i];
        if (scanningRefs && isUrl(part)) {
          referenceUrls.unshift(part); // Prepend to keep order
        } else {
          scanningRefs = false; // Stopped finding URLs, everything else left is prompt
          promptParts.unshift(part); // Prepend to keep order
        }
      }

      // Join prompt parts (if split by delimiter inside quotes, the parser kept them together, 
      // but if user had weird tab separation in prompt, we join with space)
      let prompt = promptParts.join(' ');

      // Cleanup: Excel sometimes adds extra quotes around the whole block even after parsing if not careful, 
      // though our parser handles standard CSV quotes.
      // Just a final sanity trim.
      prompt = prompt.replace(/^"+|"+$/g, ''); 

      const item: EvaluationItem = {
        id: `row-${index}`,
        modelA_Url,
        modelB_Url,
        prompt: prompt || undefined,
        referenceUrls: referenceUrls.length > 0 ? referenceUrls : undefined,
        type: 'unknown',
        // BLIND TESTING: Randomly swap A and B for display 50% of the time
        isSwapped: Math.random() > 0.5
      };

      // Only add if we successfully identified at least one model URL
      if (item.modelA_Url && isUrl(item.modelA_Url)) {
        items.push(item);
      }
    });

    return { items, modelNames };
  };

  const handleStart = () => {
    setError(null);
    if (!inputText.trim()) {
      setError("Please paste your data first.");
      return;
    }

    const { items, modelNames } = parseInput(inputText);

    if (items.length === 0) {
      setError("Could not recognize valid data rows. Ensure URLs are in the last two columns.");
      return;
    }

    // Default to 'Anonymous' if empty
    const finalName = userName.trim() || "Anonymous";

    // Save name for next time
    localStorage.setItem('eval_username', finalName);
    onStart(items, finalName, modelNames);
  };

  const downloadConfig = () => {
    if (!inputText.trim()) return;
    const blob = new Blob([inputText], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `eval_data_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const loadSample = () => {
    setInputText(SAMPLE_CSV);
    setError(null);
  };

  if (savedSession) {
    return (
      <div className="max-w-2xl mx-auto p-6 animate-in zoom-in-95 duration-300 flex flex-col items-center justify-center h-full">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 p-8 w-full text-center">
          <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <AlertTriangle size={40} />
          </div>

          <h2 className="text-2xl font-bold text-slate-800 mb-2">Unfinished Evaluation Found</h2>
          <p className="text-slate-500 mb-8">
            It looks like your browser refreshed or closed unexpectedly.<br/>
            We saved your progress. Would you like to continue where you left off?
          </p>

          <div className="flex flex-col gap-3">
            <button 
              onClick={onResume}
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-lg shadow-lg shadow-blue-200 transition-all flex items-center justify-center gap-2"
            >
              <Play size={24} fill="currentColor" />
              Resume Evaluation
            </button>

            <button 
              onClick={onDiscardSession}
              className="w-full py-3 bg-white hover:bg-slate-50 text-slate-500 hover:text-red-600 border border-slate-200 hover:border-red-200 rounded-xl font-medium transition-all flex items-center justify-center gap-2"
            >
              <RotateCcw size={18} />
              Discard and Start New
            </button>
          </div>
        </div>
        <p className="mt-8 text-slate-400 text-sm">Your progress is stored locally in your browser.</p>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto p-6 animate-in fade-in slide-in-from-bottom-4 duration-500 h-full flex flex-col justify-center">

      {/* Header Section */}
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-slate-900 mb-2 tracking-tight">New Evaluation Session</h1>
        <p className="text-slate-500 max-w-2xl mx-auto">
          Single player mode: Paste data and vote. <br/> Team mode: Collect CSV results from everyone and use the Dashboard.
        </p>

        <div className="flex justify-center gap-4 mt-6">
          <button 
            onClick={onGoToHistory}
            className="bg-white hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg font-medium text-sm flex items-center gap-2 transition-colors border border-slate-200"
          >
            <History size={16} /> Past Results
          </button>
          <button 
            onClick={onGoToAnalysis}
            className="bg-indigo-50 hover:bg-indigo-100 text-indigo-700 px-4 py-2 rounded-lg font-medium text-sm flex items-center gap-2 transition-colors border border-indigo-200"
          >
            <PieChart size={16} /> Open Analysis Dashboard
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input Area */}
        <div className="lg:col-span-8 flex flex-col gap-4">
          <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden flex flex-col h-full transition-all">

            <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex items-center gap-4">
              <div className="flex items-center gap-2 text-slate-600 font-medium">
                <User size={18} />
                <span>Your Name <span className="text-slate-400 font-normal text-xs">(Optional)</span>:</span>
              </div>
              <input 
                type="text" 
                value={userName}
                onChange={(e) => setUserName(e.target.value)}
                placeholder="e.g. Alice (Default: Anonymous)"
                className="flex-1 px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="flex-1 relative min-h-[300px]">
              <textarea
                className="w-full h-full p-6 bg-white font-mono text-sm leading-relaxed resize-none focus:outline-none text-slate-700 placeholder:text-slate-300"
                placeholder={`Paste your data here (Excel copy/paste works best).\n\nParsing Rules:\n1. Supports multiline prompts (if quoted, standard Excel behavior).\n2. Last 2 columns = Model URLs.\n3. Middle columns = Reference Images.\n4. First column = Prompt.\n\n*Note: "Model A" and "Model B" positions will be randomized during voting for blind testing.`}
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                spellCheck={false}
              />
              {inputText.length === 0 && (
                <button 
                  onClick={loadSample}
                  className="absolute bottom-6 right-6 text-slate-400 hover:text-blue-600 text-xs font-medium flex items-center gap-1 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100 hover:border-blue-200 transition-all"
                >
                  <Info size={14} /> Try Example Data
                </button>
              )}
            </div>

            {error && (
              <div className="px-6 py-3 bg-red-50 border-t border-red-100 text-red-600 text-sm flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-between items-center">
              <button
                onClick={downloadConfig}
                className="text-slate-500 hover:text-slate-800 text-sm font-medium flex items-center gap-2 px-2 py-1 rounded transition-colors"
              >
                <Download size={16} />
                <span>Backup Input</span>
              </button>

              <button
                onClick={handleStart}
                disabled={!inputText.trim()}
                className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-semibold shadow-lg shadow-slate-900/10 transition-all transform hover:-translate-y-0.5 active:translate-y-0"
              >
                <span>Start Evaluation</span>
                <ArrowRight size={18} />
              </button>
            </div>
          </div>
        </div>

        {/* Guide / Visual Helper */}
        <div className="lg:col-span-4 flex flex-col justify-center">
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
            <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <FileSpreadsheet className="text-green-600" size={20} />
              Supported Formats
            </h3>
            <div className="space-y-6">

              <div className="group">
                <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Scenario 1: Standard</div>
                <div className="flex gap-2 text-xs font-mono overflow-x-auto pb-2">
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap">Prompt</span>
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap text-slate-400">Reference?</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model A</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model B</span>
                </div>
              </div>

              <div className="group">
                <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Scenario 2: Multi-Reference</div>
                <div className="flex gap-2 text-xs font-mono overflow-x-auto pb-2">
                  <span className="bg-slate-100 border px-2 py-1 rounded whitespace-nowrap">Prompt</span>
                  <span className="bg-green-50 border border-green-200 text-green-700 px-2 py-1 rounded whitespace-nowrap">Ref 1</span>
                  <span className="bg-green-50 border border-green-200 text-green-700 px-2 py-1 rounded whitespace-nowrap">Ref 2...</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model A</span>
                  <span className="bg-blue-50 border border-blue-200 text-blue-700 px-2 py-1 rounded whitespace-nowrap">Model B</span>
                </div>
                <p className="text-[10px] text-slate-400 mt-1">We automatically detect any number of reference URLs between the Prompt and the Models.</p>
              </div>

            </div>
            <div className="mt-6 pt-4 border-t border-slate-100">
              <p className="text-xs text-slate-400 leading-relaxed">
                <Command size={12} className="inline mr-1"/>
                Tip: The last two columns are always treated as the Models to evaluate. Multiline prompts (Excel style) are fully supported.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SetupScreen;

import React, { useState, useEffect } from 'react';
import { Layers, ChevronRight } from 'lucide-react';
import SetupScreen from './components/SetupScreen';
import VotingScreen from './components/VotingScreen';
import ResultsScreen from './components/ResultsScreen';
import AnalysisScreen from './components/AnalysisScreen';
import HistoryScreen from './components/HistoryScreen';
import { AppState, EvaluationItem, HistorySession, VoteRecord, VoteType } from './types';

const STORAGE_KEY = 'modeleval_session';
const HISTORY_KEY = 'modeleval_history';

export default function App() {
  const [appState, setAppState] = useState<AppState>('setup');
  const [items, setItems] = useState<EvaluationItem[]>([]);
  const [votes, setVotes] = useState<VoteRecord[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [userName, setUserName] = useState('');
  const [modelNames, setModelNames] = useState({ a: 'Model A', b: 'Model B' });
  const [hasSavedSession, setHasSavedSession] = useState(false);
  const [sessionId, setSessionId] = useState<string>('');

  // History State
  const [history, setHistory] = useState<HistorySession[]>([]);

  // Load History on Mount
  useEffect(() => {
    const savedHistory = localStorage.getItem(HISTORY_KEY);
    if (savedHistory) {
      try {
        setHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  // Check for saved session on load
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setHasSavedSession(true);
    }
  }, [appState]);

  // Auto-save current progress
  useEffect(() => {
    if (appState === 'voting' && items.length > 0) {
      const sessionData = {
        items,
        votes,
        currentIndex,
        userName,
        modelNames,
        timestamp: Date.now(),
        sessionId // Persist the ID
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(sessionData));
    }
  }, [items, votes, currentIndex, appState, userName, modelNames, sessionId]);

  // Save to History when session is complete (moved to results)
  const saveToHistory = (completedVotes: VoteRecord[]) => {
    if (!sessionId || items.length === 0) return;

    const newEntry: HistorySession = {
      id: sessionId,
      timestamp: Date.now(),
      userName: userName || 'Anonymous',
      modelNames,
      items,
      votes: completedVotes
    };

    setHistory(prev => {
      // Avoid duplicates: if session ID exists, update it, otherwise push new
      const exists = prev.find(h => h.id === sessionId);
      const updated = exists 
        ? prev.map(h => h.id === sessionId ? newEntry : h)
        : [...prev, newEntry];

      localStorage.setItem(HISTORY_KEY, JSON.stringify(updated));
      return updated;
    });
  };

  const resumeSession = () => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setItems(data.items);
        setVotes(data.votes);
        setCurrentIndex(data.currentIndex);
        setUserName(data.userName || '');
        if (data.modelNames) setModelNames(data.modelNames);
        setSessionId(data.sessionId || `session-${Date.now()}`); // Ensure ID exists
        setAppState('voting');
      } catch (e) {
        console.error("Failed to parse saved session");
      }
    }
  };

  const discardSession = () => {
    if (confirm("Are you sure you want to discard your previous progress? This cannot be undone.")) {
      localStorage.removeItem(STORAGE_KEY);
      setHasSavedSession(false);
    }
  };

  const handleStart = (parsedItems: EvaluationItem[], name: string, parsedNames?: { a: string, b: string }) => {
    setItems(parsedItems);
    setUserName(name);
    if (parsedNames) setModelNames(parsedNames);
    else setModelNames({ a: 'Model A', b: 'Model B' });

    // Generate unique ID for this session
    setSessionId(`session-${Date.now()}`);

    setAppState('voting');
    setCurrentIndex(0);
    setVotes([]);
  };

  const handleVote = (vote: VoteType) => {
    const currentItem = items[currentIndex];

    const newVote: VoteRecord = {
      itemId: currentItem.id,
      vote,
      timestamp: Date.now(),
      user: userName
    };

    const updatedVotes = [...votes, newVote];
    setVotes(updatedVotes);

    if (currentIndex < items.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // Session Complete
      saveToHistory(updatedVotes);
      setAppState('results');
    }
  };

  const handleReset = () => {
    if (confirm("Are you sure? This will clear your current session data.")) {
      setAppState('setup');
      setItems([]);
      setVotes([]);
      setCurrentIndex(0);
      setModelNames({ a: 'Model A', b: 'Model B' });
      setSessionId('');
      localStorage.removeItem(STORAGE_KEY);
      setHasSavedSession(false);
    }
  };

  const handleEndSessionEarly = () => {
    if (votes.length > 0) {
      saveToHistory(votes);
      setAppState('results');
    } else {
      handleReset();
    }
  };

  // History Management
  const clearHistory = () => {
    if (confirm("Delete ALL history? This cannot be undone.")) {
      localStorage.removeItem(HISTORY_KEY);
      setHistory([]);
    }
  };

  const deleteSession = (id: string) => {
    if (confirm("Delete this session?")) {
      const updated = history.filter(h => h.id !== id);
      setHistory(updated);
      localStorage.setItem(HISTORY_KEY, JSON.stringify(updated));
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans selection:bg-blue-100">
      {/* Navbar */}
      <nav className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 sticky top-0 z-50">
        <div className="flex items-center gap-2 text-slate-800 cursor-pointer" onClick={() => appState !== 'voting' && setAppState('setup')}>
          <div className="bg-blue-600 text-white p-1.5 rounded-lg">
            <Layers size={20} />
          </div>
          <span className="font-bold text-lg tracking-tight">ModelEval Pro</span>
        </div>

        {/* Breadcrumbs */}
        <div className="hidden md:flex items-center gap-2 text-sm font-medium text-slate-400">
          <span className={appState === 'setup' || appState === 'analysis' || appState === 'history' ? 'text-blue-600' : ''}>Setup</span>
          <ChevronRight size={14} />
          <span className={appState === 'voting' ? 'text-blue-600' : ''}>Evaluate</span>
          <ChevronRight size={14} />
          <span className={appState === 'results' ? 'text-blue-600' : ''}>Results</span>
        </div>
      </nav>

      {/* Main Container */}
      <main className="h-[calc(100vh-64px)] overflow-auto">
        {appState === 'setup' && (
          <div className="h-full flex items-center justify-center">
            <SetupScreen 
              onStart={handleStart} 
              onGoToAnalysis={() => setAppState('analysis')}
              onGoToHistory={() => setAppState('history')}
              savedSession={hasSavedSession}
              onResume={resumeSession}
              onDiscardSession={discardSession}
            />
          </div>
        )}

        {appState === 'analysis' && (
          <div className="h-full py-10">
            <AnalysisScreen onBack={() => setAppState('setup')} />
          </div>
        )}

        {appState === 'history' && (
          <div className="h-full py-10">
            <HistoryScreen 
              history={history}
              onBack={() => setAppState('setup')}
              onClearHistory={clearHistory}
              onDeleteSession={deleteSession}
            />
          </div>
        )}

        {appState === 'voting' && items.length > 0 && (
          <VotingScreen 
            item={items[currentIndex]}
            currentIndex={currentIndex}
            totalItems={items.length}
            onVote={handleVote}
            onEnd={handleEndSessionEarly}
          />
        )}

        {appState === 'results' && (
          <div className="h-full py-10">
            <ResultsScreen 
              votes={votes} 
              items={items}
              onReset={handleReset} 
              userName={userName}
              modelNames={modelNames}
            />
          </div>
        )}
      </main>
    </div>
  );
}
